 69→ * Check if a session is in the ACTIVE phase (generator running, can send messages).
 70→ * Use this instead of manually checking `session.generator && session.sendMessage`.
 71→ */
 72→export function isSessionActive(session: SessionState | undefined): session is SessionState & {
 73→  generator: AsyncIterator<SDKMessage>;
 74→  sendMessage: (message: string) => void;
 75→} {
 76→  return !!session?.generator && !!session?.sendMessage;
 77→}
