102→  async query(sessionId: string, prompt: string, options: QueryOptions): Promise<void> {
103→    const tQueryStart = Date.now();
104→    console.log(`[TIMING][query] START session=${sessionId} promptLength=${prompt.length}`);
105→    if (blockIfNotInitialized(sessionId)) return;
106→
107→    const session = claudeSessions.get(sessionId);
108→    const modelChanged = session?.currentModel !== options.model;
109→    const maxThinkingTokensChanged =
110→      session?.currentMaxThinkingTokens !== options.maxThinkingTokens;
111→    const settingsChangedFlag = settingsChanged(session?.currentSettings, options);
112→
113→    if (session) {
114→      session.turnId = options.turnId;
115→      session.cwd = options.cwd;
116→    }
117→
118→    const canReuse =
119→      isSessionActive(session) && options.shouldResetGenerator !== true && !settingsChangedFlag;
120→
121→    if (canReuse) {
122→      console.log(
123→        `[TIMING][query] REUSE session=${sessionId} decisionTime=${Date.now() - tQueryStart}ms`
124→      );
125→
126→      // Hot-swap model if it changed
127→      if (modelChanged && session) {
128→        const query = claudeQueries.get(sessionId);
129→        if (query) {
130→          const envVars = options.providerEnvVars ? parseEnvString(options.providerEnvVars) : {};
131→          const mappedModel = mapModelForProvider(options.model, envVars);
132→          console.log(
133→            `Model changed from ${session.currentModel} to ${options.model}, using setModel callback`
134→          );
135→          try {
136→            await query.setModel(mappedModel);
137→            const updatedSession = claudeSessions.get(sessionId);
138→            if (updatedSession) updatedSession.currentModel = options.model;
139→          } catch (error) {
140→            console.error(`Failed to update model: ${getErrorMessage(error)}`);
141→          }
142→        }
143→      }
144→
145→      // Hot-swap maxThinkingTokens if it changed
146→      const query = claudeQueries.get(sessionId);
147→      if (maxThinkingTokensChanged && session && query) {
148→        try {
149→          await query.setMaxThinkingTokens(options.maxThinkingTokens ?? null);
150→          session.currentMaxThinkingTokens = options.maxThinkingTokens;
151→        } catch (error) {
152→          console.error(`Failed to update maxThinkingTokens: ${getErrorMessage(error)}`);
153→        }
154→      }
155→
156→      // Update permission mode if provided
157→      if (query && options.permissionMode) {
158→        try {
159→          await query.setPermissionMode(options.permissionMode as PermissionMode);
160→        } catch (error) {
161→          console.error(`Failed to update permission mode: ${getErrorMessage(error)}`);
162→        }
163→      }
164→
165→      // Push the new prompt into the existing generator
166→      // isSessionActive type guard narrows sendMessage to be defined
167→      session.sendMessage(prompt);
168→    } else {
169→      const reason = !session
170→        ? "new session"
171→        : !isSessionActive(session)
172→          ? "no active generator"
173→          : options.shouldResetGenerator
174→            ? "should reset generator"
175→            : "settings changed";
176→      console.log(
177→        `[TIMING][query] NEW_GENERATOR session=${sessionId} reason="${reason}" decisionTime=${Date.now() - tQueryStart}ms`
178→      );
179→
180→      if (isSessionActive(session)) {
181→        terminateSession(sessionId);
182→      }
183→
184→      const newSession: SessionState = {
185→        currentSettings: {
186→          providerEnvVars: options.providerEnvVars,
187→          additionalDirectories: options.additionalDirectories,
188→          chromeEnabled: options.chromeEnabled,
189→          strictDataPrivacy: options.strictDataPrivacy,
190→        },
191→        currentModel: options.model,
192→        currentMaxThinkingTokens: options.maxThinkingTokens,
193→        turnId: options.turnId,
194→        cwd: options.cwd,
195→      };
196→      claudeSessions.set(sessionId, newSession);
197→
198→      void this.processWithGenerator(sessionId, prompt, options);
199→    }
200→  }
201→
202→  async cancel(sessionId: string): Promise<void> {
203→    console.log("Handling Claude cancel request for session:", sessionId);
204→    if (blockIfNotInitialized(sessionId)) return;
205→
206→    const existingQuery = claudeQueries.get(sessionId);
207→    const session = claudeSessions.get(sessionId);
208→
209→    if (isSessionActive(session) && existingQuery) {
210→      console.log(`Force-closing query for session ${sessionId}`);
211→
212→      // 1. Flag cancellation so the post-loop path persists the cancelled message
213→      session.cancelledByUser = true;
214→
215→      // 2. Create checkpoint before process dies
216→      if (session.turnId && session.cwd) {
217→        createCheckpoint(sessionId, session.turnId, "end", session.cwd, "claudeHandler");
218→      }
219→
220→      // 3. Force kill: close() terminates CLI subprocess + all children + MCP transports
221→      existingQuery.close();
222→
223→      // 4. Signal prompt generator to stop — finally block owns cleanup
224→      terminateSession(sessionId);
225→    } else {
226→      console.log(`No active session found for ${sessionId} to cancel`);
227→    }
228→  }
