389→  /**
390→   * Creates an async-generator-backed Claude SDK session.
391→   * Uses a message queue for multi-turn conversations.
392→   */
393→  private async processWithGenerator(
394→    sessionId: string,
395→    initialPrompt: string,
396→    options: QueryOptions
397→  ): Promise<void> {
398→    const tProcessStart = Date.now();
399→    const generatorId = `${sessionId}/${tProcessStart}`;
400→    const session = claudeSessions.get(sessionId);
401→    if (!session) {
402→      console.error(`[${generatorId}] Session ${sessionId} not found`);
403→      return;
404→    }
405→    console.log(`[TIMING][${generatorId}] processWithGenerator START`);
406→
407→    // --- Message queue for multi-turn conversations ---
408→    const promptQueue = new AsyncQueue<string>([initialPrompt]);
409→
410→    session.sendMessage = (message: string) => {
411→      console.log(`[${generatorId}] Pushing message to queue`);
412→      promptQueue.push(message);
413→    };
414→
415→    session.sendTerminate = () => {
416→      console.log(`[${generatorId}] Sending terminate signal`);
417→      promptQueue.close();
418→    };
419→
420→    // Mutable context accumulated during the streaming loop.
421→    const ctx = createStreamContext();
422→
423→    try {
424→      // Build environment using shared env-builder
425→      const tEnvStart = Date.now();
426→      const envForClaude = buildAgentEnvironment({
427→        providerEnvVars: options?.providerEnvVars,
428→        opendevsEnv: options?.opendevsEnv,
429→        ghToken: options?.ghToken,
430→        extraEnv: { CLAUDE_CODE_ENABLE_TASKS: "true" },
431→      });
432→      console.log(
433→        `[TIMING][${generatorId}] buildAgentEnvironment took ${Date.now() - tEnvStart}ms`
434→      );
435→
436→      // Resume is now passed in turn/start params from the backend (which owns the DB
437→      // and knows the agent_session_id). The agent-server is stateless — no DB lookups.
438→      if (options.resume) {
439→        console.log(
440→          `[RESUME-DEBUG][${generatorId}] Attempting resume with agent_session_id=${options.resume} for session=${sessionId}`
441→        );
442→      }
443→
444→      // Build SDK options using the dedicated builder
445→      const tSdkOptsStart = Date.now();
446→      const sdkOptions = buildSdkOptions(sessionId, envForClaude, options);
447→      console.log(`[TIMING][${generatorId}] buildSdkOptions took ${Date.now() - tSdkOptsStart}ms`);
448→
449→      const promptInput = buildPromptIterable(promptQueue, sessionId);
450→
451→      // Start the SDK query
452→      console.log(
453→        `[TIMING][${generatorId}] SDK spawn starting (elapsed since processStart: ${Date.now() - tProcessStart}ms)`
454→      );
455→      console.log(
456→        `[RESUME-DEBUG][${generatorId}] SDK options: resume=${sdkOptions.resume ?? "none"} cwd=${sdkOptions.cwd} model=${sdkOptions.model} permissionMode=${sdkOptions.permissionMode}`
457→      );
458→      const tSdkSpawn = Date.now();
459→      const queryResult = claudeSDK({ prompt: promptInput, options: sdkOptions });
460→      console.log(
461→        `[TIMING][${generatorId}] claudeSDK() constructor returned in ${Date.now() - tSdkSpawn}ms`
462→      );
463→
464→      claudeQueries.set(sessionId, queryResult);
465→      session.generator = queryResult[Symbol.asyncIterator]();
466→
467→      // Per-message options (constant for the lifetime of this generator)
468→      const msgOpts: ProcessMessageOptions = {
469→        sessionId,
470→        generatorId,
471→        model: options.model || "opus",
472→        isResume: !!options.resume,
473→      };
474→
475→      // Stream messages back to the frontend and persist to DB.
476→      // IMPORTANT: Persist to DB BEFORE notifying frontend, so messages
477→      // are in the DB when the frontend receives the event and fetches them.
478→      const tStreamStart = Date.now();
479→      for await (const message of queryResult) {
480→        ctx.messageCount++;
481→        if (ctx.firstMessageTime === null) {
482→          ctx.firstMessageTime = Date.now();
483→          console.log(
484→            `[TIMING][${generatorId}] FIRST_MESSAGE received after ${ctx.firstMessageTime - tSdkSpawn}ms (type=${(message as any)?.type})`
485→          );
486→        }
487→        // Deserialize, persist, and forward to frontend.
488→        // See message-processor.ts for the critical side-effect ordering.
489→        if (message) {
490→          const cleanMessage = deserializeMessage(message, generatorId);
491→          if (!cleanMessage) continue;
492→
493→          processMessage(cleanMessage, ctx, session, msgOpts);
494→
495→          // Log per-message timing for first 5 messages, then every 10th
496→          if (ctx.messageCount <= 5 || ctx.messageCount % 10 === 0) {
497→            console.log(
498→              `[TIMING][${generatorId}] msg#${ctx.messageCount} type=${cleanMessage.type}${cleanMessage.type === "result" ? "/" + cleanMessage.subtype : ""} elapsed=${Date.now() - tStreamStart}ms`
499→            );
500→          }
501→        }
502→      }
503→
504→      console.log(
505→        `[TIMING][${generatorId}] STREAM_COMPLETE messages=${ctx.messageCount} totalStreamTime=${Date.now() - tStreamStart}ms totalProcessTime=${Date.now() - tProcessStart}ms`
506→      );
507→
508→      // Post-loop: stream ended cleanly (prompt queue closed or SDK finished).
509→      // Turn-level idle is already set by processMessage on result/success.
510→      // This handles conversation-end: cancel persistence only.
511→      if (
512→        handleCancellation(sessionId, "claude", options.model || "opus", !!session.cancelledByUser)
513→      ) {
514→        console.log(`[${generatorId}] Session cancelled by user: ${sessionId}`);
515→        return;
516→      }
517→      console.log(`[${generatorId}] Stream completed: ${sessionId}`);
518→    } catch (error) {
519→      // Cancel takes priority — abort signal can surface as a thrown error.
520→      if (
521→        handleCancellation(sessionId, "claude", options.model || "opus", !!session.cancelledByUser)
522→      ) {
523→        console.log(`[${generatorId}] Session cancelled by user (catch): ${sessionId}`);
524→        return;
525→      }
526→
527→      // Post-success process exit: the CLI shuts down between turns and the
528→      // SDK reports the signal-based exit as an error. Expected cleanup, not failure.
529→      if (ctx.querySucceeded) {
530→        console.log(`[${generatorId}] Process exited after successful query (expected cleanup)`);
531→        return;
532→      }
533→
534→      // Genuine error — check if this generator still owns the session.
535→      // A rapid re-query can replace the session before the catch runs.
536→      const errorName = error instanceof Error ? error.name : "non-Error";
537→      const errorStack =
538→        error instanceof Error ? error.stack?.split("\n").slice(0, 5).join("\n") : "no stack";
539→      const extraProps =
540→        error instanceof Error
541→          ? Object.getOwnPropertyNames(error)
542→              .filter((k) => !["message", "stack", "name"].includes(k))
543→              .map((k) => `${k}=${JSON.stringify((error as any)[k])}`)
544→              .join(" ")
545→          : "";
546→
547→      const classified = classifyError(error);
548→
549→      console.error(
550→        `[${generatorId}] Error in Claude query [${classified.category}]:`,
551→        classified.message
552→      );
553→      console.error(
554→        `[${generatorId}] Error details:`,
555→        `name=${errorName}`,
556→        `wasResume=${!!options.resume}`,
557→        `resumeId=${options.resume ?? "none"}`,
558→        `querySucceeded=${ctx.querySucceeded}`,
559→        `messageCount=${ctx.messageCount}`,
560→        extraProps ? `extraProps={${extraProps}}` : "extraProps={}"
561→      );
562→      console.error(`[${generatorId}] Stack (top 5):\n${errorStack}`);
563→
564→      if (claudeSessions.owns(sessionId, session)) {
565→        handleQueryError(sessionId, "claude", error, (c) => {
566→          if (c.category !== "process_exit") return c.message;
567→          const parts: string[] = [c.message];
568→          if (options.resume) parts.push("(resumed session)");
569→          if (ctx.messageCount > 0) {
570→            parts.push(`after ${ctx.messageCount} message${ctx.messageCount !== 1 ? "s" : ""}`);
571→          } else {
572→            parts.push("before receiving any messages");
573→          }
574→          if (ctx.lastResultError) parts.push(`— ${ctx.lastResultError}`);
575→          if (extraProps) parts.push(`[${extraProps}]`);
576→          return parts.join(" ");
577→        });
578→      }
579→    } finally {
580→      // Only clean up if this generator still owns the session.
581→      // A rapid re-query can replace the session before this finally runs;
582→      // blindly deleting would wipe the new session's state.
583→      if (claudeSessions.owns(sessionId, session)) {
584→        claudeQueries.delete(sessionId);
585→        claudeSessions.delete(sessionId);
586→      }
587→    }
588→  }
589→}
