 80→// ─── Package Manager Detection ──────────────────────────────────
 81→
 82→interface PackageManager {
 83→  command: string;
 84→  args: string[];
 85→}
 86→
 87→/**
 88→ * Detect the package manager from lockfile presence in the workspace.
 89→ * Returns null if no package.json exists (nothing to install).
 90→ */
 91→export function detectPackageManager(dir: string): PackageManager | null {
 92→  // Check lockfiles in priority order (bun first — project default)
 93→  if (fs.existsSync(path.join(dir, "bun.lock")) || fs.existsSync(path.join(dir, "bun.lockb"))) {
 94→    return { command: "bun", args: ["install", "--frozen-lockfile"] };
 95→  }
 96→  if (fs.existsSync(path.join(dir, "yarn.lock"))) {
 97→    return { command: "yarn", args: ["install", "--frozen-lockfile"] };
 98→  }
 99→  if (fs.existsSync(path.join(dir, "pnpm-lock.yaml"))) {
100→    return { command: "pnpm", args: ["install", "--frozen-lockfile"] };
101→  }
102→  if (fs.existsSync(path.join(dir, "package-lock.json"))) {
103→    return { command: "npm", args: ["ci"] };
104→  }
105→  // package.json exists but no lockfile — try npm install
106→  if (fs.existsSync(path.join(dir, "package.json"))) {
107→    return { command: "npm", args: ["install"] };
108→  }
109→  return null;
110→}
