 33→// ---- Command Dispatch ----
 34→
 35→export async function runCommand(
 36→  command: CommandName,
 37→  params: QueryParams
 38→): Promise<CommandResult> {
 39→  return (
 40→    match(command)
 41→      .with("sendMessage", () => handleSendMessage(params))
 42→      .with("stopSession", () => handleStopSession(params))
 43→      // ---- PTY commands ----
 44→      .with("pty:spawn", () => {
 45→        const id = readString(params, "id");
 46→        const cmd = readString(params, "command") ?? "bash";
 47→        const args = Array.isArray(params.args) ? (params.args as string[]) : [];
 48→        const cols = readNumber(params, "cols") ?? 80;
 49→        const rows = readNumber(params, "rows") ?? 24;
 50→        const cwd = readString(params, "cwd");
 51→        if (!id) throw new Error("pty:spawn requires id");
 52→
 53→        const ptyId = spawnPty({ id, command: cmd, args, cols, rows, cwd });
 54→        return { commandId: ptyId };
 55→      })
 56→      .with("pty:write", () => {
 57→        const id = readString(params, "id");
 58→        if (!id) throw new Error("pty:write requires id");
 59→        const data = Array.isArray(params.data) ? (params.data as number[]) : undefined;
 60→        if (!data) throw new Error("pty:write requires data (number[])");
 61→
 62→        writeToPty(id, data);
 63→        return {};
 64→      })
 65→      .with("pty:resize", () => {
 66→        const id = readString(params, "id");
 67→        const cols = readNumber(params, "cols");
 68→        const rows = readNumber(params, "rows");
 69→        if (!id || cols === undefined || rows === undefined) {
 70→          throw new Error("pty:resize requires id, cols, and rows");
 71→        }
 72→
 73→        resizePty(id, cols, rows);
 74→        return {};
 75→      })
 76→      .with("pty:kill", () => {
 77→        const id = readString(params, "id");
 78→        if (!id) throw new Error("pty:kill requires id");
 79→
 80→        killPty(id);
 81→        return {};
 82→      })
 83→      // ---- File system commands ----
 84→      .with("fs:watch", async () => {
 85→        const workspacePath = readString(params, "workspacePath");
 86→        if (!workspacePath) throw new Error("fs:watch requires workspacePath");
 87→
 88→        await watchWorkspace(workspacePath);
 89→        return {};
 90→      })
 91→      .with("fs:unwatch", async () => {
 92→        const workspacePath = readString(params, "workspacePath");
 93→        if (!workspacePath) throw new Error("fs:unwatch requires workspacePath");
 94→
 95→        await unwatchWorkspace(workspacePath);
 96→        return {};
 97→      })
 98→      // ---- Git commands ----
 99→      .with("git:clone", () => {
100→        // Git clone is handled via HTTP POST /api/repos, not WS commands.
101→        // This arm exists so the exhaustive match compiles; reject at runtime.
102→        throw new Error("git:clone is not available as a WS command — use POST /api/repos instead");
103→      })
104→      // ---- Route-delegated commands ----
105→      .with("createWorkspace", async () => {
106→        const repositoryId = readString(params, "repository_id");
107→        if (!repositoryId) throw new Error("createWorkspace requires repository_id");
108→        const body: Record<string, unknown> = { repository_id: repositoryId };
109→        const sourceBranch = readString(params, "source_branch");
110→        const prUrl = readString(params, "pr_url");
111→        const prTitle = readString(params, "pr_title");
112→        const targetBranch = readString(params, "target_branch");
113→        if (sourceBranch) body.source_branch = sourceBranch;
114→        if (params.pr_number != null) body.pr_number = params.pr_number;
115→        if (prUrl) body.pr_url = prUrl;
116→        if (prTitle) body.pr_title = prTitle;
117→        if (targetBranch) body.target_branch = targetBranch;
118→        const result = (await delegateToRoute("POST", "/api/workspaces", body)) as { id?: string };
119→        return { commandId: result.id };
120→      })
121→      .with("retrySetup", async () => {
122→        const workspaceId = readString(params, "workspaceId");
123→        if (!workspaceId) throw new Error("retrySetup requires workspaceId");
124→        await delegateToRoute("POST", `/api/workspaces/${workspaceId}/retry-setup`);
125→        return {};
126→      })
127→      .with("openPenFile", async () => {
128→        const workspaceId = readString(params, "workspaceId");
129→        const filePath = readString(params, "filePath");
130→        if (!workspaceId || !filePath)
131→          throw new Error("openPenFile requires workspaceId and filePath");
132→        await delegateToRoute("POST", `/api/workspaces/${workspaceId}/open-pen-file`, {
