141→// ---- sendMessage ----
142→
143→function handleSendMessage(params: QueryParams): CommandResult {
144→  const sessionId = readString(params, "sessionId");
145→  const content = readString(params, "content");
146→  const model = readString(params, "model");
147→  if (!sessionId || !content) {
148→    throw new Error("sendMessage requires sessionId and content");
149→  }
150→
151→  // 1. Persist the user message
152→  const result = writeUserMessage(sessionId, content, model);
153→  if (!result.success) throw new Error(result.error);
154→  invalidate(["workspaces", "sessions", "session", "messages", "stats"], {
155→    sessionIds: [sessionId],
156→  });
157→
158→  // 2. Forward to agent-server (fire-and-forget — ACK already sent)
159→  const agentType = (readString(params, "agentType") || "claude") as "claude" | "codex";
160→
161→  // Look up the existing agent_session_id so the SDK resumes the same
162→  // conversation rather than starting a new one.
163→  const db = getDatabase();
164→  const session = getSessionRaw(db, sessionId);
165→  const existingAgentSessionId = session?.agent_session_id ?? null;
166→
167→  if (!agentService.isConnected()) {
168→    handleAgentError(sessionId, agentType, new Error("Agent server is disconnected"));
169→    return { commandId: result.messageId };
170→  }
171→
172→  agentService
173→    .forwardTurn({
174→      sessionId,
175→      agentType,
176→      prompt: content,
177→      options: buildTurnOptions(params, model, existingAgentSessionId) as Parameters<
178→        typeof agentService.forwardTurn
179→      >[0]["options"],
180→    })
181→    .then((response) => {
182→      if (!response.accepted) {
183→        handleAgentRejection(sessionId, agentType, response.reason);
184→      }
185→    })
186→    .catch((err) => {
187→      handleAgentError(sessionId, agentType, err);
188→    });
189→
190→  return { commandId: result.messageId };
191→}
