195→async function handleStopSession(params: QueryParams): Promise<CommandResult> {
196→  const sessionId = readString(params, "sessionId");
197→  if (!sessionId) throw new Error("stopSession requires sessionId");
198→
199→  const db = getDatabase();
200→  const session = getSessionRaw(db, sessionId);
201→  if (!session) throw new Error("Session not found");
202→
203→  if (agentService.isConnected()) {
204→    try {
205→      await agentService.stopSession({ sessionId });
206→    } catch (err) {
207→      console.error("[CommandHandler] Failed to stop on agent-server:", err);
