212→  db.prepare("UPDATE sessions SET status = 'idle', updated_at = datetime('now') WHERE id = ?").run(
213→    sessionId
214→  );
215→  invalidate(["workspaces", "sessions", "session", "stats"], { sessionIds: [sessionId] });
216→  return {};
217→}
