 56→// ============================================================================
 57→// processMessage
 58→// ============================================================================
 59→
 60→/**
 61→ * Processes a single deserialized SDK message.
 62→ *
 63→ * Side effects (in critical order):
 64→ * 1. Capture agent_session_id (one-shot, first message only, skip on resume)
 65→ * 2. Emit canonical message events (assistant, tool_result)
 66→ * 3. Send to frontend via JSON-RPC notification
 67→ * 4. Classify stop_reason and send error (AFTER sendMessage — content before error banner)
 68→ * 5. Detect result/success → set ctx.querySucceeded, emit session.idle
 69→ * 6. Detect result/error_during_execution → set ctx.lastResultError
 70→ *
 71→ * The agent-server is stateless — no DB writes. The backend persists messages
 72→ * and updates session status by consuming canonical events via the WS tunnel.
 73→ */
 74→export function processMessage(
 75→  cleanMessage: Record<string, unknown>,
 76→  ctx: StreamContext,
 77→  session: SessionState,
 78→  opts: ProcessMessageOptions
 79→): void {
 80→  // Extract common fields from the deserialized SDK message.
 81→  // cleanMessage is Record<string, unknown> (JSON.parse output), so
 82→  // we narrow once here instead of scattering `as` casts throughout.
 83→  const msg = cleanMessage.message as
 84→    | { id?: string; role?: string; content?: unknown; stop_reason?: string }
 85→    | undefined;
 86→  const parentToolUseId =
 87→    typeof cleanMessage.parent_tool_use_id === "string" ? cleanMessage.parent_tool_use_id : null;
 88→
 89→  // 1. One-shot: capture SDK session_id on the first message.
 90→  // CRITICAL: Skip capture during resume attempts. When a resume
 91→  // fails (result/error_during_execution), the SDK returns a NEW
 92→  // session_id that is useless. If we captured it, we'd overwrite
 93→  // the original working agent_session_id — permanently lost.
 94→  if (!session.agentSessionIdCaptured && cleanMessage.session_id && !opts.isResume) {
 95→    const agentSessionId = String(cleanMessage.session_id);
 96→
 97→    try {
 98→      // Emit canonical agent.session_id event — backend persists to DB.
 99→      // Set captured flag AFTER emission so a failed send allows retry on next message.
100→      EventBroadcaster.emitAgentSessionId(opts.sessionId, agentSessionId);
101→      session.agentSessionIdCaptured = true;
102→      console.log(`[${opts.generatorId}] Captured agent_session_id: ${agentSessionId}`);
103→    } catch (error) {
104→      console.error(
105→        `[${opts.generatorId}] Failed to emit agent_session_id:`,
106→        getErrorMessage(error)
107→      );
108→    }
109→  }
110→
111→  // 2. Emit canonical message events for assistant and tool_result messages
112→  if (cleanMessage.type === "assistant" && msg) {
113→    const assistantMsgId = msg.id || "unknown";
114→    EventBroadcaster.emitAssistantMessage(
115→      opts.sessionId,
116→      "claude",
117→      {
118→        id: assistantMsgId,
119→        role: "assistant",
120→        content: msg.content,
121→        stop_reason: msg.stop_reason ?? null,
122→        parent_tool_use_id: parentToolUseId,
123→      },
124→      opts.model
125→    );
126→  }
127→
128→  if (cleanMessage.type === "user" && msg) {
129→    const content = msg.content;
130→    const hasToolResult =
131→      Array.isArray(content) && content.some((b: any) => b?.type === "tool_result");
132→    if (hasToolResult) {
133→      const toolResultMsgId = msg.id || "unknown";
134→      EventBroadcaster.emitToolResultMessage(
135→        opts.sessionId,
136→        "claude",
137→        {
138→          id: toolResultMsgId,
139→          role: "user",
140→          content: msg.content,
141→          parent_tool_use_id: parentToolUseId,
142→        },
143→        opts.model
144→      );
145→    }
146→  }
