342→// ─── Manifest & Task Endpoints ──────────────────────────────
343→
344→// Get parsed manifest + normalized tasks for a workspace
345→app.get("/workspaces/:id/manifest", withWorkspace, (c) => {
346→  const workspace = c.get("workspace");
347→  const workspacePath = c.get("workspacePath");
348→  if (!workspace.root_path) {
349→    return c.json({ manifest: null, tasks: [] });
350→  }
351→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
352→  if (!manifest) return c.json({ manifest: null, tasks: [] });
353→  const tasks = getNormalizedTasks(manifest);
354→  return c.json({ manifest, tasks });
355→});
