357→// Retry failed setup
358→app.post("/workspaces/:id/retry-setup", withWorkspace, (c) => {
359→  const db = getDatabase();
360→  const workspace = c.get("workspace");
361→  const workspacePath = c.get("workspacePath");
362→
363→  if (workspace.setup_status !== "failed") {
364→    throw new ValidationError("Can only retry when setup_status is failed");
365→  }
366→
367→  if (!workspace.root_path) {
368→    throw new ValidationError("Repository path not found");
369→  }
370→
371→  // Re-read manifest (AI agent may have fixed it, or it was added to repo root via settings)
372→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
373→  const setupCmd = manifest ? getSetupCommand(manifest) : null;
374→  if (!setupCmd || !manifest) {
375→    db.prepare(
376→      "UPDATE workspaces SET setup_status = 'none', error_message = NULL, updated_at = datetime('now') WHERE id = ?"
377→    ).run(workspace.id);
378→    return c.json({ setup_status: "none" });
379→  }
380→
381→  db.prepare(
382→    "UPDATE workspaces SET setup_status = 'running', error_message = NULL, updated_at = datetime('now') WHERE id = ?"
383→  ).run(workspace.id);
384→
385→  const setupEnv = getOpenDevsEnv(manifest, {
386→    id: workspace.id,
387→    rootPath: workspace.root_path,
388→    workspacePath,
389→  });
390→  runSetupScript(db, workspace.id, setupCmd, setupEnv, workspacePath);
391→
392→  return c.json({ setup_status: "running" });
393→});
394→
395→// Get setup logs
396→app.get("/workspaces/:id/setup-logs", withWorkspace, (c) => {
397→  const workspace = c.get("workspace");
398→  const setupLogPath = path.join(os.tmpdir(), `opendevs-${workspace.id}-setup.log`);
399→  try {
400→    if (!fs.existsSync(setupLogPath)) return c.json({ logs: null });
401→    const logs = fs.readFileSync(setupLogPath, "utf8");
402→    return c.json({ logs });
403→  } catch {
404→    return c.json({ logs: null });
405→  }
406→});
407→
408→// Run a task — validates task exists, returns info for frontend PTY spawn
409→app.post("/workspaces/:id/tasks/:name/run", withWorkspace, (c) => {
410→  const workspace = c.get("workspace");
411→  const workspacePath = c.get("workspacePath");
412→  const taskName = c.req.param("name");
413→
414→  if (!workspace.root_path) {
415→    throw new ValidationError("Repository path not found");
416→  }
417→
418→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
419→  if (!manifest) throw new NotFoundError("No opendevs.json manifest found");
420→
421→  const tasks = getNormalizedTasks(manifest);
422→  const task = tasks.find((t) => t.name === taskName);
423→  if (!task) throw new NotFoundError(`Task "${taskName}" not found in manifest`);
424→
425→  const ptyId = `task-${workspace.id}-${taskName}-${Date.now()}`;
426→  const env = {
427→    ...(manifest.env ?? {}),
428→    ...task.env,
429→    OPENDEVS_ROOT_PATH: workspace.root_path,
430→    OPENDEVS_WORKSPACE_PATH: workspacePath,
431→    OPENDEVS_WORKSPACE_ID: workspace.id,
432→  };
433→
434→  return c.json({
435→    ptyId,
436→    command: task.command,
437→    cwd: workspacePath,
438→    env,
439→    persistent: task.persistent,
440→    mode: task.mode,
441→  });
442→});
443→
444→export default app;
