 9→/**
10→ * Get repository initials for display
11→ * @param repoName - Repository name (e.g., "box-ide" or "owner/repo")
12→ * @returns Uppercase initials (e.g., "BI" or "OR")
13→ */
14→export function getRepoInitials(repoName: string): string {
15→  const parts = repoName.split(/[-_\s]/);
16→  if (parts.length >= 2) {
17→    return (parts[0][0] + parts[1][0]).toUpperCase();
18→  }
19→  return repoName.slice(0, 2).toUpperCase();
