22→/**
23→ * Get color scheme for repository badge based on name hash
24→ * @param repoName - Repository name
25→ * @returns Semantic design token classes
26→ */
27→export function getRepoColor(repoName: string): { bg: string; text: string } {
28→  const hash = repoName.split("").reduce((acc, char) => acc + char.charCodeAt(0), 0);
29→  // Use semantic tokens so colors follow the design system theme.
30→  const schemes = [
31→    { bg: "bg-primary/20", text: "text-primary" },
32→    { bg: "bg-secondary/30", text: "text-secondary-foreground" },
33→    { bg: "bg-accent/30", text: "text-accent-foreground" },
34→    { bg: "bg-muted", text: "text-muted-foreground" },
35→    { bg: "bg-sidebar-accent", text: "text-sidebar-foreground" },
36→  ];
37→  return schemes[hash % schemes.length];
38→}
