10→/**
11→ * Persist a user message and mark session as working.
12→ * Returns the result; caller must call invalidate() on success.
13→ */
14→export function writeUserMessage(
15→  sessionId: string,
16→  content: string,
17→  model?: string
18→): { success: true; messageId: string } | { success: false; error: string } {
19→  const db = getDatabase();
20→  const session = getSessionRaw(db, sessionId);
21→  if (!session) {
22→    return { success: false, error: "Session not found" };
23→  }
24→
25→  const messageId = uuidv7();
26→  const sentAt = new Date().toISOString();
27→  const messageModel = model || "opus";
28→
29→  db.transaction(() => {
30→    db.prepare(
31→      `
32→      INSERT INTO messages (id, session_id, role, content, sent_at, model)
33→      VALUES (?, ?, 'user', ?, ?, ?)
34→    `
35→    ).run(messageId, sessionId, content, sentAt, messageModel);
36→
37→    db.prepare(
38→      "UPDATE sessions SET status = 'working', last_user_message_at = ?, error_message = NULL, error_category = NULL, updated_at = datetime('now') WHERE id = ?"
39→    ).run(sentAt, sessionId);
40→  })();
41→
42→  return { success: true, messageId };
43→}
