304→    queryFn: () => WorkspaceService.fetchPRStatus(workspaceId!),
305→    enabled: !!workspaceId && ghInstalled && ghAuthenticated,
306→    staleTime: 10_000,
307→    refetchInterval: (query) => {
308→      // While agent is working: poll every 30s to detect PR creation/updates.
309→      if (sessionStatus === "working") return 30_000;
310→
311→      // After agent stops: CI checks typically run 2-15min. Poll every 60s
312→      // while CI is pending so the user sees updates without manual refresh.
313→      const data = query.state.data as PRStatus | null | undefined;
314→      if (data?.has_pr && data?.ci_status === "pending") return 60_000;
