434→/**
435→ * Archive workspace mutation with optimistic update
436→ *
437→ * Flow:
438→ * 1. User clicks archive → UI updates IMMEDIATELY (workspace removed from list)
439→ * 2. HTTP request sent in background
440→ * 3. Success: Cache already correct, refetch confirms
441→ * 4. Error: Rollback to previous state, show error
442→ */
443→export function useArchiveWorkspace() {
444→  const queryClient = useQueryClient();
445→  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
446→
447→  return useMutation({
448→    mutationFn: (workspaceId: string) => WorkspaceService.archive(workspaceId),
449→
450→    // Optimistic update: Remove workspace from UI immediately
451→    onMutate: async (workspaceId: string) => {
452→      // Cancel any outgoing refetches (so they don't overwrite our optimistic update)
453→      await queryClient.cancelQueries({ queryKey });
454→
455→      // Snapshot the previous value
456→      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);
457→
458→      // Optimistically remove the workspace from the list
459→      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
460→        if (!old) return old;
461→        return produce(old, (draft) => {
462→          for (const repo of draft) {
463→            const index = repo.workspaces.findIndex((w) => w.id === workspaceId);
464→            if (index !== -1) {
465→              repo.workspaces.splice(index, 1);
466→              break;
467→            }
468→          }
469→        });
470→      });
471→
472→      // Return context with the previous value for rollback
473→      return { previousData };
474→    },
475→
476→    // If mutation fails, roll back to the previous value
477→    onError: (_err, _workspaceId, context) => {
478→      if (context?.previousData) {
479→        queryClient.setQueryData(queryKey, context.previousData);
480→      }
481→    },
482→
483→    onSuccess: (_data, workspaceId) => {
484→      track("workspace_archived", { workspace_id: workspaceId });
485→    },
486→
487→    // Always refetch after error or success to ensure consistency
488→    onSettled: () => {
489→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
490→    },
491→  });
492→}
