 21→// ============================================================================
 22→// Message Format Mapping
 23→// ============================================================================
 24→
 25→/**
 26→ * Maps a Codex ThreadItem to Claude-compatible content blocks.
 27→ * The frontend renders messages using Claude's format (TextBlock, ToolUseBlock,
 28→ * ToolResultBlock, ThinkingBlock), so we produce the same shape.
 29→ */
 30→function mapItemToContentBlocks(item: ThreadItem): unknown[] {
 31→  return match(item)
 32→    .with({ type: "agent_message" }, (i) => [{ type: "text", text: i.text }])
 33→    .with({ type: "reasoning" }, (i) => [{ type: "thinking", thinking: i.text }])
 34→    .with({ type: "command_execution" }, (cmd) => {
 35→      const toolUseId = `codex-cmd-${cmd.id}`;
 36→      const blocks: unknown[] = [
 37→        {
 38→          type: "tool_use",
 39→          id: toolUseId,
 40→          name: "Bash",
 41→          input: { command: cmd.command },
 42→        },
 43→      ];
 44→      if (cmd.status === "completed" || cmd.status === "failed") {
 45→        blocks.push({
 46→          type: "tool_result",
 47→          tool_use_id: toolUseId,
 48→          content: cmd.aggregated_output || `Exit code: ${cmd.exit_code ?? "unknown"}`,
 49→          is_error: cmd.status === "failed" || (cmd.exit_code !== undefined && cmd.exit_code !== 0),
 50→        });
 51→      }
 52→      return blocks;
 53→    })
 54→    .with({ type: "file_change" }, (fc) => {
 55→      const toolUseId = `codex-file-${fc.id}`;
 56→      const summary = fc.changes.map((c) => `${c.kind}: ${c.path}`).join("\n");
 57→      return [
 58→        {
 59→          type: "tool_use",
 60→          id: toolUseId,
 61→          name: "Edit",
 62→          input: {
 63→            file_path: fc.changes[0]?.path ?? "unknown",
 64→            description: summary,
 65→          },
 66→        },
 67→        {
 68→          type: "tool_result",
 69→          tool_use_id: toolUseId,
 70→          content: summary,
 71→          is_error: fc.status === "failed",
 72→        },
 73→      ];
 74→    })
 75→    .with({ type: "mcp_tool_call" }, (mcp) => {
 76→      const toolUseId = `codex-mcp-${mcp.id}`;
 77→      const blocks: unknown[] = [
 78→        {
 79→          type: "tool_use",
 80→          id: toolUseId,
 81→          name: `${mcp.server}:${mcp.tool}`,
 82→          input: mcp.arguments ?? {},
 83→        },
 84→      ];
 85→      if (mcp.status === "completed" || mcp.status === "failed") {
 86→        blocks.push({
 87→          type: "tool_result",
 88→          tool_use_id: toolUseId,
 89→          content: mcp.error?.message ?? JSON.stringify(mcp.result ?? ""),
 90→          is_error: mcp.status === "failed",
 91→        });
 92→      }
 93→      return blocks;
 94→    })
 95→    .with({ type: "web_search" }, (ws) => [
 96→      {
 97→        type: "tool_use",
 98→        id: `codex-ws-${ws.id}`,
 99→        name: "WebSearch",
100→        input: { query: ws.query },
101→      },
102→    ])
103→    .with({ type: "todo_list" }, (todo) => {
104→      const text = todo.items.map((t) => `${t.completed ? "[x]" : "[ ]"} ${t.text}`).join("\n");
105→      return [{ type: "text", text: `**Plan:**\n${text}` }];
106→    })
107→    .with({ type: "error" }, (i) => [{ type: "text", text: `Error: ${i.message}` }])
108→    .otherwise((i) => {
109→      // External SDK types can gain new variants — gracefully ignore unknown items
110→      console.warn(`[codex] Unknown ThreadItem type: ${(i as any).type}`);
111→      return [];
112→    });
113→}
