 49→/** Timeout for user-facing requests that require human interaction.
 50→ *  2 minutes allows users time to read multi-option questions and deliberate.
 51→ *  There is no UI countdown, so this must be generous. */
 52→const USER_FACING_TIMEOUT_MS = 120_000;
 53→
 54→/** Timeout for data-fetching requests that should resolve quickly */
 55→const DATA_QUERY_TIMEOUT_MS = 10_000;
 56→
 57→/** Timeout for simulator screenshot — native capture + JPEG
 58→ *  encoding + base64 transfer. Typically <2s but allow headroom. */
 59→const SIMULATOR_SCREENSHOT_TIMEOUT_MS = 10_000;
 60→
 61→/** Timeout for simulator interactions (tap, swipe, type, key press) — HID
 62→ *  injection through the ObjC bridge is fast but include IPC buffer. */
 63→const SIMULATOR_INTERACTION_TIMEOUT_MS = 10_000;
 64→
 65→/** Timeout for simulator boot — booting a simulator and starting the MJPEG
 66→ *  stream + ObjC bridge can take 15-20s on cold boot. */
 67→const SIMULATOR_BOOT_TIMEOUT_MS = 30_000;
 68→
 69→/** Timeout for build-and-run — xcodebuild can take minutes for large projects.
 70→ *  10 minutes matches the existing builder.ts timeout. */
 71→const SIMULATOR_BUILD_TIMEOUT_MS = 600_000;
 72→
