 74→// EventBroadcaster class
 75→// ============================================================================
 76→
 77→class EventBroadcasterClass {
 78→  // Multi-tunnel: all connected clients receive notifications.
 79→  // The relay and desktop app can be connected simultaneously.
 80→  private tunnels = new Set<RpcConnection>();
 81→
 82→  attachTunnel(tunnel: RpcConnection): void {
 83→    this.tunnels.add(tunnel);
 84→    console.log(`[EventBroadcaster] Tunnel attached (${this.tunnels.size} active)`);
 85→  }
 86→
 87→  /**
 88→   * Detach a specific tunnel. If tunnel is provided, removes only that one.
 89→   * If no tunnel is provided, clears all tunnels.
 90→   */
 91→  detachTunnel(tunnel?: RpcConnection): void {
 92→    if (tunnel) {
 93→      this.tunnels.delete(tunnel);
 94→      console.log(`[EventBroadcaster] Tunnel detached (${this.tunnels.size} remaining)`);
 95→    } else {
 96→      this.tunnels.clear();
 97→      console.log("[EventBroadcaster] All tunnels cleared");
 98→    }
 99→  }
100→
101→  // ==========================================================================
102→  // OUTGOING NOTIFICATIONS (sidecar -> frontend)
103→  // ==========================================================================
104→
105→  sendMessage(response: MessageResponse): void {
106→    this.broadcastNotification(FRONTEND_NOTIFICATIONS.MESSAGE, response, "sendMessage");
107→  }
108→
109→  sendError(response: ErrorResponse): void {
110→    this.broadcastNotification(FRONTEND_NOTIFICATIONS.QUERY_ERROR, response, "sendError");
111→  }
112→
113→  sendEnterPlanModeNotification(response: EnterPlanModeNotification): void {
114→    this.broadcastNotification(
115→      FRONTEND_NOTIFICATIONS.ENTER_PLAN_MODE,
116→      response,
117→      "sendEnterPlanModeNotification"
118→    );
119→  }
120→
121→  sendStatusChanged(notification: StatusChangedNotification): void {
122→    this.broadcastNotification(
123→      FRONTEND_NOTIFICATIONS.STATUS_CHANGED,
124→      notification,
125→      "sendStatusChanged"
126→    );
127→  }
128→
129→  // ==========================================================================
130→  // CANONICAL EVENT EMISSION (agent-server protocol — dual-write period)
131→  //
132→  // These methods emit provider-neutral events defined in shared/agent-events.ts
133→  // as JSON-RPC notifications to all connected tunnels. During the dual-write
134→  // period, both the old notifications (sendMessage/sendError/etc.) and these
135→  // canonical events are emitted simultaneously.
136→  // ==========================================================================
137→
138→  /** Generic emit: broadcasts a canonical AgentEvent as a JSON-RPC notification. */
