  3→/** The status of a command execution. */
  4→type CommandExecutionStatus = "in_progress" | "completed" | "failed";
  5→/** A command executed by the agent. */
  6→type CommandExecutionItem = {
  7→    id: string;
  8→    type: "command_execution";
  9→    /** The command line executed by the agent. */
 10→    command: string;
 11→    /** Aggregated stdout and stderr captured while the command was running. */
 12→    aggregated_output: string;
 13→    /** Set when the command exits; omitted while still running. */
 14→    exit_code?: number;
 15→    /** Current status of the command execution. */
 16→    status: CommandExecutionStatus;
 17→};
 18→/** Indicates the type of the file change. */
 19→type PatchChangeKind = "add" | "delete" | "update";
 20→/** A set of file changes by the agent. */
 21→type FileUpdateChange = {
 22→    path: string;
 23→    kind: PatchChangeKind;
 24→};
 25→/** The status of a file change. */
 26→type PatchApplyStatus = "completed" | "failed";
 27→/** A set of file changes by the agent. Emitted once the patch succeeds or fails. */
 28→type FileChangeItem = {
 29→    id: string;
 30→    type: "file_change";
 31→    /** Individual file changes that comprise the patch. */
 32→    changes: FileUpdateChange[];
 33→    /** Whether the patch ultimately succeeded or failed. */
 34→    status: PatchApplyStatus;
 35→};
 36→/** The status of an MCP tool call. */
 37→type McpToolCallStatus = "in_progress" | "completed" | "failed";
 38→/**
 39→ * Represents a call to an MCP tool. The item starts when the invocation is dispatched
 40→ * and completes when the MCP server reports success or failure.
 41→ */
 42→type McpToolCallItem = {
 43→    id: string;
 44→    type: "mcp_tool_call";
 45→    /** Name of the MCP server handling the request. */
 46→    server: string;
 47→    /** The tool invoked on the MCP server. */
 48→    tool: string;
 49→    /** Arguments forwarded to the tool invocation. */
 50→    arguments: unknown;
 51→    /** Result payload returned by the MCP server for successful calls. */
 52→    result?: {
 53→        content: ContentBlock[];
 54→        structured_content: unknown;
 55→    };
 56→    /** Error message reported for failed calls. */
 57→    error?: {
 58→        message: string;
 59→    };
 60→    /** Current status of the tool invocation. */
 61→    status: McpToolCallStatus;
 62→};
 63→/** Response from the agent. Either natural-language text or JSON when structured output is requested. */
 64→type AgentMessageItem = {
 65→    id: string;
 66→    type: "agent_message";
 67→    /** Either natural-language text or JSON when structured output is requested. */
 68→    text: string;
 69→};
 70→/** Agent's reasoning summary. */
 71→type ReasoningItem = {
 72→    id: string;
 73→    type: "reasoning";
 74→    text: string;
 75→};
 76→/** Captures a web search request. Completes when results are returned to the agent. */
 77→type WebSearchItem = {
 78→    id: string;
 79→    type: "web_search";
 80→    query: string;
 81→};
 82→/** Describes a non-fatal error surfaced as an item. */
 83→type ErrorItem = {
 84→    id: string;
 85→    type: "error";
 86→    message: string;
 87→};
 88→/** An item in the agent's to-do list. */
 89→type TodoItem = {
 90→    text: string;
 91→    completed: boolean;
 92→};
 93→/**
 94→ * Tracks the agent's running to-do list. Starts when the plan is issued, updates as steps change,
 95→ * and completes when the turn ends.
 96→ */
 97→type TodoListItem = {
 98→    id: string;
 99→    type: "todo_list";
100→    items: TodoItem[];
101→};
102→/** Canonical union of thread items and their type-specific payloads. */
103→type ThreadItem = AgentMessageItem | ReasoningItem | CommandExecutionItem | FileChangeItem | McpToolCallItem | WebSearchItem | TodoListItem | ErrorItem;
104→
105→/** Emitted when a new thread is started as the first event. */
106→type ThreadStartedEvent = {
107→    type: "thread.started";
108→    /** The identifier of the new thread. Can be used to resume the thread later. */
109→    thread_id: string;
110→};
111→/**
112→ * Emitted when a turn is started by sending a new prompt to the model.
113→ * A turn encompasses all events that happen while the agent is processing the prompt.
114→ */
115→type TurnStartedEvent = {
116→    type: "turn.started";
117→};
118→/** Describes the usage of tokens during a turn. */
119→type Usage = {
120→    /** The number of input tokens used during the turn. */
121→    input_tokens: number;
122→    /** The number of cached input tokens used during the turn. */
123→    cached_input_tokens: number;
124→    /** The number of output tokens used during the turn. */
125→    output_tokens: number;
126→};
127→/** Emitted when a turn is completed. Typically right after the assistant's response. */
128→type TurnCompletedEvent = {
129→    type: "turn.completed";
130→    usage: Usage;
131→};
132→/** Indicates that a turn failed with an error. */
133→type TurnFailedEvent = {
134→    type: "turn.failed";
135→    error: ThreadError;
136→};
137→/** Emitted when a new item is added to the thread. Typically the item is initially "in progress". */
138→type ItemStartedEvent = {
139→    type: "item.started";
140→    item: ThreadItem;
141→};
142→/** Emitted when an item is updated. */
143→type ItemUpdatedEvent = {
144→    type: "item.updated";
145→    item: ThreadItem;
146→};
147→/** Signals that an item has reached a terminal state—either success or failure. */
148→type ItemCompletedEvent = {
149→    type: "item.completed";
150→    item: ThreadItem;
151→};
152→/** Fatal error emitted by the stream. */
153→type ThreadError = {
154→    message: string;
155→};
156→/** Represents an unrecoverable error emitted directly by the event stream. */
157→type ThreadErrorEvent = {
158→    type: "error";
159→    message: string;
160→};
161→/** Top-level JSONL events emitted by codex exec. */
162→type ThreadEvent = ThreadStartedEvent | TurnStartedEvent | TurnCompletedEvent | TurnFailedEvent | ItemStartedEvent | ItemUpdatedEvent | ItemCompletedEvent | ThreadErrorEvent;
163→
164→type TurnOptions = {
165→    /** JSON schema describing the expected agent output. */
166→    outputSchema?: unknown;
167→    /** AbortSignal to cancel the turn. */
