 52→/**
 53→ * Wraps an AsyncQueue of raw prompt strings into the async-iterable format
 54→ * expected by the Claude Agent SDK. Handles both plain text and JSON-encoded
 55→ * content blocks (when user attaches images).
 56→ */
 57→function buildPromptIterable(queue: AsyncQueue<string>, sessionId: string) {
 58→  return (async function* () {
 59→    for await (const message of queue) {
 60→      let content: string | unknown[] = message;
 61→      if (message && message.startsWith("[")) {
 62→        try {
 63→          const parsed = JSON.parse(message);
 64→          if (Array.isArray(parsed) && parsed.length > 0 && parsed[0]?.type) {
 65→            content = parsed;
 66→          }
 67→        } catch {
 68→          // Not valid JSON — keep as plain text string
 69→        }
 70→      }
 71→
 72→      yield {
 73→        type: "user" as const,
 74→        message: { role: "user" as const, content },
 75→        parent_tool_use_id: null,
 76→        session_id: sessionId,
 77→      };
 78→    }
 79→  })();
 80→}
