408→  /**
409→   * Broadcast a notification to all connected tunnels.
410→   * Dead tunnels (those that throw on notify) are automatically removed.
411→   */
412→  private broadcastNotification(method: string, params: unknown, label: string): void {
413→    const t0 = Date.now();
414→    for (const tunnel of this.tunnels) {
415→      try {
416→        tunnel.notify(method, params);
417→      } catch (err) {
418→        console.error(`[EventBroadcaster] ${label} failed, removing dead tunnel:`, err);
419→        this.tunnels.delete(tunnel);
420→      }
421→    }
422→    const elapsed = Date.now() - t0;
423→    if (elapsed > 5) {
424→      console.log(
425→        `[TIMING][EventBroadcaster] ${label} broadcast took ${elapsed}ms (${this.tunnels.size} tunnels)`
426→      );
427→    }
428→  }
429→
430→  /**
431→   * Race a tunnel request against a timeout. Rejects with a descriptive
432→   * error if the frontend does not respond within `ms` milliseconds.
433→   */
434→  private withTimeout<T>(promise: Promise<T>, ms: number, label: string): Promise<T> {
435→    let timerId: ReturnType<typeof setTimeout> | undefined;
436→
437→    const timeout = new Promise<never>((_, reject) => {
438→      timerId = setTimeout(() => {
439→        reject(
440→          new Error(
441→            `[EventBroadcaster] ${label} timed out after ${ms}ms -- frontend did not respond`
442→          )
443→        );
444→      }, ms);
445→    });
446→
447→    return Promise.race([promise, timeout]).finally(() => {
448→      if (timerId !== undefined) clearTimeout(timerId);
449→    });
450→  }
451→}
