 1→// sidecar/agents/claude/stream-context.ts
 2→// Mutable state accumulated during the for-await streaming loop.
 3→
 4→/**
 5→ * Mutable context accumulated during the for-await streaming loop.
 6→ * Each field has a single writer and clear lifecycle:
 7→ *
 8→ * - querySucceeded:  set once when result/success is received
 9→ * - stopReasonError: set once when classifyStopReason detects an error
10→ * - messageCount:    incremented per SDK message
11→ * - lastResultError: set when result/error_during_execution is received
12→ * - firstMessageTime: timestamp of first SDK message (ms), null until set
13→ */
14→export interface StreamContext {
15→  querySucceeded: boolean;
16→  stopReasonError: boolean;
17→  messageCount: number;
18→  lastResultError: string | null;
19→  firstMessageTime: number | null;
20→}
21→
22→export function createStreamContext(): StreamContext {
23→  return {
24→    querySucceeded: false,
25→    stopReasonError: false,
26→    messageCount: 0,
27→    lastResultError: null,
28→    firstMessageTime: null,
29→  };
30→}
