  1→// backend/src/services/agent/event-handler.ts
  2→// Receives canonical AgentEvent notifications from the agent-client and
  3→// dispatches them to persistence (DB writes) and WS push (query invalidation).
  4→//
  5→// This is the single entry point for all agent → backend data flow.
  6→// Each event is handled: persist first, then invalidate (ordering matters).
  7→//
  8→// Created via createAgentEventHandler() — a factory that injects the
  9→// respondToAgent dependency, breaking the circular import with service.ts.
 10→
 11→import { match } from "ts-pattern";
 12→import type { AgentEvent } from "@shared/agent-events";
 13→import type { QueryResource } from "@shared/types/query-protocol";
 14→import { invalidate } from "../query-engine";
 15→import { relay } from "./tool-relay";
 16→import {
 17→  persistAssistantMessage,
 18→  persistToolResultMessage,
 19→  persistMessageResult,
 20→  persistMessageCancelled,
 21→  persistSessionStarted,
 22→  persistSessionIdle,
 23→  persistSessionError,
 24→  persistSessionCancelled,
 25→  persistAgentSessionId,
 26→  type WriteResult,
 27→} from "./persistence";
 28→
 29→// ---- Types ----
 30→
 31→type RespondToAgentFn = (params: {
 32→  sessionId: string;
 33→  requestId: string;
 34→  result: unknown;
 35→}) => Promise<void>;
 36→
 37→export type AgentEventHandler = (event: AgentEvent) => void;
 38→
 39→// ---- Resource groups for invalidation ----
 40→
 41→const SESSION_RESOURCES: QueryResource[] = ["workspaces", "sessions", "session", "stats"];
 42→const MESSAGE_RESOURCES: QueryResource[] = ["messages", "session"];
 43→
 44→// ---- Helpers ----
 45→
 46→/** Persist an event and invalidate subscriptions if the write succeeded. */
 47→function persistAndInvalidate(
 48→  result: WriteResult<unknown>,
 49→  resources: QueryResource[],
 50→  sessionId: string
 51→): void {
 52→  if (result.ok) {
 53→    invalidate(resources, { sessionIds: [sessionId] });
 54→  }
 55→}
 56→
 57→// ---- Factory ----
 58→
 59→/**
 60→ * Create an agent event handler with injected dependencies.
 61→ *
 62→ * The respondToAgent function is injected to break the circular dependency
 63→ * between this module and service.ts. The composition root (service.ts)
 64→ * provides the concrete implementation: client.sendTurnRespond().
 65→ */
 66→export function createAgentEventHandler(deps: {
 67→  respondToAgent: RespondToAgentFn;
 68→}): AgentEventHandler {
 69→  const { respondToAgent } = deps;
 70→
 71→  return function handleAgentEvent(event: AgentEvent): void {
 72→    match(event)
 73→      // ── Session lifecycle ─────────────────────────────────────────────
 74→      .with({ type: "session.started" }, (e) => {
 75→        console.log(`[AgentEvent] session.started: session=${e.sessionId} agent=${e.agentType}`);
 76→        persistAndInvalidate(persistSessionStarted(e), SESSION_RESOURCES, e.sessionId);
 77→      })
 78→      .with({ type: "session.idle" }, (e) => {
 79→        console.log(`[AgentEvent] session.idle: session=${e.sessionId}`);
 80→        persistAndInvalidate(persistSessionIdle(e), SESSION_RESOURCES, e.sessionId);
 81→      })
 82→      .with({ type: "session.error" }, (e) => {
 83→        console.log(`[AgentEvent] session.error: session=${e.sessionId} error=${e.error}`);
 84→        persistAndInvalidate(persistSessionError(e), SESSION_RESOURCES, e.sessionId);
 85→      })
 86→      .with({ type: "session.cancelled" }, (e) => {
 87→        console.log(`[AgentEvent] session.cancelled: session=${e.sessionId}`);
 88→        persistAndInvalidate(persistSessionCancelled(e), SESSION_RESOURCES, e.sessionId);
 89→      })
 90→
 91→      // ── Messages ──────────────────────────────────────────────────────
 92→      .with({ type: "message.assistant" }, (e) => {
 93→        console.log(`[AgentEvent] message.assistant: session=${e.sessionId} msgId=${e.message.id}`);
 94→        persistAndInvalidate(persistAssistantMessage(e), MESSAGE_RESOURCES, e.sessionId);
 95→      })
 96→      .with({ type: "message.tool_result" }, (e) => {
 97→        console.log(
 98→          `[AgentEvent] message.tool_result: session=${e.sessionId} msgId=${e.message.id}`
 99→        );
100→        persistAndInvalidate(persistToolResultMessage(e), MESSAGE_RESOURCES, e.sessionId);
101→      })
102→      .with({ type: "message.result" }, (e) => {
103→        console.log(`[AgentEvent] message.result: session=${e.sessionId} subtype=${e.subtype}`);
104→        persistMessageResult(e);
105→      })
106→      .with({ type: "message.cancelled" }, (e) => {
107→        console.log(`[AgentEvent] message.cancelled: session=${e.sessionId}`);
108→        persistAndInvalidate(
109→          persistMessageCancelled(e),
110→          ["messages", "sessions", "session", "stats"],
111→          e.sessionId
112→        );
113→      })
114→
115→      // ── Interaction requests ──────────────────────────────────────────
116→      .with({ type: "request.opened" }, (e) => {
117→        console.log(
118→          `[AgentEvent] request.opened: session=${e.sessionId} requestId=${e.requestId} type=${e.requestType}`
119→        );
120→      })
121→      .with({ type: "request.resolved" }, (e) => {
122→        console.log(
123→          `[AgentEvent] request.resolved: session=${e.sessionId} requestId=${e.requestId}`
124→        );
125→      })
126→
127→      // ── Tool relay ────────────────────────────────────────────────────
128→      .with({ type: "tool.request" }, (e) => {
129→        console.log(
130→          `[AgentEvent] tool.request: session=${e.sessionId} method=${e.method} requestId=${e.requestId}`
131→        );
132→        void relayToolRequest(e, respondToAgent);
133→      })
134→
135→      // ── Metadata ──────────────────────────────────────────────────────
136→      .with({ type: "agent.session_id" }, (e) => {
137→        console.log(
138→          `[AgentEvent] agent.session_id: session=${e.sessionId} agentSessionId=${e.agentSessionId}`
139→        );
140→        persistAndInvalidate(persistAgentSessionId(e), SESSION_RESOURCES, e.sessionId);
141→      })
142→
143→      .exhaustive();
144→  };
145→}
146→
147→// ---- Tool relay internal ----
148→
149→async function relayToolRequest(
150→  event: AgentEvent & { type: "tool.request" },
151→  respondToAgent: RespondToAgentFn
152→): Promise<void> {
153→  const { sessionId, requestId, method } = event;
154→
155→  try {
156→    const result = await relay(event);
157→    await respondToAgent({ sessionId, requestId, result });
158→    console.log(`[AgentEvent] tool.request resolved: requestId=${requestId} method=${method}`);
159→  } catch (err) {
160→    console.error(`[AgentEvent] tool.request failed: requestId=${requestId} method=${method}`, err);
161→    try {
162→      await respondToAgent({
163→        sessionId,
164→        requestId,
165→        result: { error: err instanceof Error ? err.message : "Tool relay failed" },
166→      });
167→    } catch (respondErr) {
168→      console.error(
169→        `[AgentEvent] Failed to send error response to agent: requestId=${requestId}`,
170→        respondErr
171→      );
172→    }
173→  }
174→}
