  1→// backend/src/services/agent/persistence.ts
  2→// Database write functions for persisting canonical agent events.
  3→//
  4→// Adapted from sidecar/db/session-writer.ts. Key differences:
  5→// - Uses backend's getDatabase() (not sidecar's)
  6→// - No notifyBackend() calls (backend handles WS push via invalidate())
  7→// - No FrontendClient calls (backend pushes via query-engine directly)
  8→// - Takes event objects instead of positional args
  9→//
 10→// All functions are synchronous (better-sqlite3 is synchronous).
 11→// Callers (event-handler.ts) call invalidate() after persistence succeeds.
 12→
 13→import { getDatabase } from "../../lib/database";
 14→import { uuidv7 } from "@shared/lib/uuid";
 15→import { getErrorMessage } from "@shared/lib/errors";
 16→import type {
 17→  MessageAssistantEvent,
 18→  MessageToolResultEvent,
 19→  MessageResultEvent,
 20→  MessageCancelledEvent,
 21→  SessionStartedEvent,
 22→  SessionIdleEvent,
 23→  SessionErrorEvent,
 24→  SessionCancelledEvent,
 25→  AgentSessionIdEvent,
 26→} from "@shared/agent-events";
 27→
 28→// ============================================================================
 29→// WriteResult type (mirrors sidecar's pattern)
 30→// ============================================================================
 31→
 32→export type WriteResult<T = string> = { ok: true; value: T } | { ok: false; error: string };
 33→
 34→// ============================================================================
 35→// Message writes
 36→// ============================================================================
 37→
 38→/**
 39→ * Save an assistant message to the messages table.
 40→ * Mirrors sidecar saveAssistantMessage() logic:
 41→ * - Generates a local UUID7 message ID
 42→ * - Stores flat content array, except for cancelled messages which get an envelope
 43→ * - Records the agent_message_id and parent_tool_use_id for linking
 44→ */
 45→export function persistAssistantMessage(event: MessageAssistantEvent): WriteResult {
 46→  const db = getDatabase();
 47→  const messageId = uuidv7();
 48→  const sentAt = new Date().toISOString();
 49→
 50→  // Store flat content array for normal messages. For "cancelled" messages,
 51→  // write envelope so the frontend can detect cancellation from DB content.
 52→  const contentPayload =
 53→    event.message.stop_reason === "cancelled"
 54→      ? { message: { stop_reason: "cancelled" }, blocks: event.message.content ?? [] }
 55→      : (event.message.content ?? []);
 56→  const content = JSON.stringify(contentPayload);
 57→
 58→  try {
 59→    db.prepare(
 60→      `INSERT INTO messages (id, session_id, role, content, sent_at, model, agent_message_id, parent_tool_use_id)
 61→       VALUES (?, ?, 'assistant', ?, ?, ?, ?, ?)`
 62→    ).run(
 63→      messageId,
 64→      event.sessionId,
 65→      content,
 66→      sentAt,
 67→      event.model || null,
 68→      event.message.id || null,
 69→      event.message.parent_tool_use_id || null
 70→    );
 71→    return { ok: true, value: messageId };
 72→  } catch (error) {
 73→    const msg = getErrorMessage(error);
 74→    console.error(`[AgentPersistence] Failed to save assistant message:`, msg);
 75→    return { ok: false, error: msg };
 76→  }
 77→}
 78→
 79→/**
 80→ * Save a tool_result message (role='user') to the messages table.
 81→ * These contain tool execution results that link tool_use blocks to their outputs.
 82→ */
 83→export function persistToolResultMessage(event: MessageToolResultEvent): WriteResult {
 84→  const db = getDatabase();
 85→  const messageId = uuidv7();
 86→  const sentAt = new Date().toISOString();
 87→  const content = JSON.stringify(event.message.content ?? []);
 88→
 89→  try {
 90→    db.prepare(
 91→      `INSERT INTO messages (id, session_id, role, content, sent_at, agent_message_id, parent_tool_use_id)
 92→       VALUES (?, ?, 'user', ?, ?, ?, ?)`
 93→    ).run(
 94→      messageId,
 95→      event.sessionId,
 96→      content,
 97→      sentAt,
 98→      event.message.id || null,
 99→      event.message.parent_tool_use_id || null
100→    );
101→    return { ok: true, value: messageId };
102→  } catch (error) {
103→    const msg = getErrorMessage(error);
104→    console.error(`[AgentPersistence] Failed to save tool_result message:`, msg);
105→    return { ok: false, error: msg };
106→  }
107→}
108→
109→/**
110→ * Handle message.result events. No DB write needed — this is informational
111→ * (success/error_during_execution subtypes). Session status transitions are
112→ * handled by separate session.idle / session.error events.
113→ */
114→export function persistMessageResult(_event: MessageResultEvent): void {
115→  // No-op: message.result is informational only.
116→  // Session status is managed by session.idle / session.error events.
117→}
118→
119→/**
120→ * Persist a cancellation: insert a cancelled assistant message marker
121→ * and set session status to idle.
122→ *
123→ * The cancelled message uses the envelope format so the frontend can detect
124→ * cancellation on reload (the "Turn interrupted" label in AssistantTurn).
125→ */
126→export function persistMessageCancelled(event: MessageCancelledEvent): WriteResult {
127→  const db = getDatabase();
128→  const messageId = uuidv7();
129→  const sentAt = new Date().toISOString();
130→
131→  // Empty cancelled message with envelope so frontend detects cancellation
132→  const content = JSON.stringify({
133→    message: { stop_reason: "cancelled" },
134→    blocks: [],
135→  });
136→
137→  try {
138→    db.transaction(() => {
139→      db.prepare(
140→        `INSERT INTO messages (id, session_id, role, content, sent_at, cancelled_at)
141→         VALUES (?, ?, 'assistant', ?, ?, ?)`
142→      ).run(messageId, event.sessionId, content, sentAt, sentAt);
143→
144→      db.prepare(
145→        `UPDATE sessions SET status = 'idle', error_message = NULL, error_category = NULL, updated_at = datetime('now') WHERE id = ?`
146→      ).run(event.sessionId);
147→    })();
148→
149→    return { ok: true, value: messageId };
150→  } catch (error) {
151→    const msg = getErrorMessage(error);
152→    console.error(`[AgentPersistence] Failed to persist message.cancelled:`, msg);
153→    return { ok: false, error: msg };
154→  }
155→}
156→
157→// ============================================================================
158→// Session status writes
159→// ============================================================================
160→
161→/**
162→ * Update session status to "working" when a turn starts.
163→ * Only updates if the session is not already working (idempotent).
164→ */
165→export function persistSessionStarted(event: SessionStartedEvent): WriteResult<void> {
166→  const db = getDatabase();
167→
168→  try {
169→    db.prepare(
170→      `UPDATE sessions SET status = 'working', error_message = NULL, error_category = NULL, updated_at = datetime('now')
171→       WHERE id = ? AND status != 'working'`
172→    ).run(event.sessionId);
173→    return { ok: true, value: undefined };
174→  } catch (error) {
175→    const msg = getErrorMessage(error);
176→    console.error(`[AgentPersistence] Failed to persist session.started:`, msg);
177→    return { ok: false, error: msg };
178→  }
179→}
180→
181→/** Update session status to "idle" when a turn completes. */
182→export function persistSessionIdle(event: SessionIdleEvent): WriteResult<void> {
183→  const db = getDatabase();
184→
185→  try {
186→    db.prepare(
187→      `UPDATE sessions SET status = 'idle', error_message = NULL, error_category = NULL, updated_at = datetime('now') WHERE id = ?`
188→    ).run(event.sessionId);
189→    return { ok: true, value: undefined };
190→  } catch (error) {
191→    const msg = getErrorMessage(error);
192→    console.error(`[AgentPersistence] Failed to persist session.idle:`, msg);
193→    return { ok: false, error: msg };
194→  }
195→}
196→
197→/** Update session status to "error" with error details. */
198→export function persistSessionError(event: SessionErrorEvent): WriteResult<void> {
199→  const db = getDatabase();
200→
201→  try {
202→    db.prepare(
203→      `UPDATE sessions SET status = 'error', error_message = ?, error_category = ?, updated_at = datetime('now') WHERE id = ?`
204→    ).run(event.error, event.category, event.sessionId);
205→    return { ok: true, value: undefined };
206→  } catch (error) {
207→    const msg = getErrorMessage(error);
