  1→// sidecar/agents/claude/claude-session.ts
  2→// Session state management for Claude agent: active sessions, queries,
  3→// settings comparison, termination, and session reuse logic.
  4→
  5→import type { Query, SDKMessage } from "@anthropic-ai/claude-agent-sdk";
  6→import type { QueryOptions } from "../registry";
  7→import { SessionStore } from "../session-store";
  8→
  9→// ============================================================================
 10→// Types
 11→// ============================================================================
 12→
 13→/**
 14→ * Mutable session record accumulated during a Claude SDK lifecycle.
 15→ *
 16→ * Lifecycle phases (fields set in each phase):
 17→ *
 18→ *   IDLE (freshly created via query() → claudeSessions.set):
 19→ *     currentSettings, currentModel, currentMaxThinkingTokens, turnId, cwd
 20→ *     generator/sendMessage/sendTerminate are undefined
 21→ *
 22→ *   ACTIVE (processWithGenerator running):
 23→ *     All fields populated. generator + sendMessage + sendTerminate set
 24→ *     by processWithGenerator after SDK query starts.
 25→ *
 26→ *   TERMINATED (terminateSession called, awaiting finally cleanup):
 27→ *     generator + sendMessage deleted. sendTerminate fired.
 28→ *     Session object is kept alive so processWithGenerator's finally block
 29→ *     can compare `currentSession === session` (reference identity check)
 30→ *     to avoid clobbering a rapid re-query's fresh session.
 31→ *
 32→ * Use `isSessionActive(session)` to check if a session is in the ACTIVE phase.
 33→ */
 34→export interface SessionState {
 35→  generator?: AsyncIterator<SDKMessage>;
 36→  sendMessage?: (message: string) => void;
 37→  sendTerminate?: () => void;
 38→  currentSettings?: {
 39→    providerEnvVars?: string;
 40→    additionalDirectories?: string[];
 41→    chromeEnabled?: boolean;
 42→    strictDataPrivacy?: boolean;
 43→  };
 44→  currentModel?: string;
 45→  currentMaxThinkingTokens?: number;
 46→  turnId?: string;
 47→  cwd?: string;
 48→  /** One-shot flag: true after the first SDK message's session_id has been persisted to DB */
 49→  agentSessionIdCaptured?: boolean;
 50→  /** Set by cancel() before close() — checked by post-loop path to persist cancellation */
 51→  cancelledByUser?: boolean;
 52→}
 53→
 54→// ============================================================================
 55→// Session Stores
 56→// ============================================================================
 57→
 58→/** Active Claude sessions keyed by sessionId. */
 59→export const claudeSessions = new SessionStore<SessionState>();
 60→
 61→/** Active Claude SDK Query objects keyed by sessionId. */
 62→export const claudeQueries = new SessionStore<Query>();
 63→
 64→// ============================================================================
 65→// Public API
 66→// ============================================================================
 67→
 68→/**
 69→ * Check if a session is in the ACTIVE phase (generator running, can send messages).
 70→ * Use this instead of manually checking `session.generator && session.sendMessage`.
 71→ */
 72→export function isSessionActive(session: SessionState | undefined): session is SessionState & {
 73→  generator: AsyncIterator<SDKMessage>;
 74→  sendMessage: (message: string) => void;
 75→} {
 76→  return !!session?.generator && !!session?.sendMessage;
 77→}
 78→
 79→/**
 80→ * Compares old session settings with new options to determine
 81→ * if the generator needs to be recreated.
 82→ */
 83→export function settingsChanged(
 84→  oldSettings: SessionState["currentSettings"],
 85→  newSettings: QueryOptions | undefined
 86→): boolean {
 87→  if (!oldSettings) return true;
 88→
 89→  if (oldSettings.providerEnvVars !== newSettings?.providerEnvVars) {
 90→    return true;
 91→  }
 92→
 93→  const oldDirs = oldSettings.additionalDirectories ?? [];
 94→  const newDirs = newSettings?.additionalDirectories ?? [];
 95→  if (oldDirs.length !== newDirs.length) return true;
 96→  for (let i = 0; i < oldDirs.length; i++) {
 97→    if (oldDirs[i] !== newDirs[i]) return true;
 98→  }
 99→
100→  if ((oldSettings.chromeEnabled ?? false) !== (newSettings?.chromeEnabled ?? false)) {
101→    return true;
102→  }
103→
104→  if ((oldSettings.strictDataPrivacy ?? false) !== (newSettings?.strictDataPrivacy ?? false)) {
105→    return true;
106→  }
107→
108→  return false;
109→}
110→
111→/**
112→ * Terminates the generator for a session (sends terminate signal,
113→ * cleans up generator and sendMessage references).
114→ */
