395→  // ==========================================================================
396→  // Internal helpers
397→  // ==========================================================================
398→
399→  /** Generic typed RPC: send a request to the frontend with a timeout. */
400→  private async rpc<TRes>(method: string, params: unknown, timeoutMs: number): Promise<TRes> {
401→    return this.withTimeout<TRes>(
402→      this.requireTunnel().request(method, params) as Promise<TRes>,
403→      timeoutMs,
404→      method
405→    );
406→  }
407→
408→  /** Returns the first available tunnel, or throws if none are connected. */
409→  private requireTunnel(): RpcConnection {
410→    const first = this.tunnels.values().next().value;
411→    if (!first) {
412→      throw new Error("EventBroadcaster tunnel not attached.");
413→    }
414→    return first;
415→  }
416→
417→  /**
418→   * Broadcast a notification to all connected tunnels.
419→   * Dead tunnels (those that throw on notify) are automatically removed.
420→   */
421→  private broadcastNotification(method: string, params: unknown, label: string): void {
422→    const t0 = Date.now();
423→    for (const tunnel of this.tunnels) {
424→      try {
425→        tunnel.notify(method, params);
426→      } catch (err) {
427→        console.error(`[EventBroadcaster] ${label} failed, removing dead tunnel:`, err);
428→        this.tunnels.delete(tunnel);
429→      }
430→    }
431→    const elapsed = Date.now() - t0;
432→    if (elapsed > 5) {
433→      console.log(
434→        `[TIMING][EventBroadcaster] ${label} broadcast took ${elapsed}ms (${this.tunnels.size} tunnels)`
435→      );
436→    }
437→  }
438→
439→  /**
440→   * Race a tunnel request against a timeout. Rejects with a descriptive
441→   * error if the frontend does not respond within `ms` milliseconds.
442→   */
443→  private withTimeout<T>(promise: Promise<T>, ms: number, label: string): Promise<T> {
444→    let timerId: ReturnType<typeof setTimeout> | undefined;
445→
446→    const timeout = new Promise<never>((_, reject) => {
447→      timerId = setTimeout(() => {
448→        reject(
449→          new Error(
450→            `[EventBroadcaster] ${label} timed out after ${ms}ms -- frontend did not respond`
451→          )
452→        );
453→      }, ms);
454→    });
455→
456→    return Promise.race([promise, timeout]).finally(() => {
457→      if (timerId !== undefined) clearTimeout(timerId);
458→    });
459→  }
460→}
