  6→import { getErrorMessage } from "@shared/lib/errors";
  7→import { EventBroadcaster } from "../../event-broadcaster";
  8→import { classifyStopReason } from "../lifecycle";
  9→import type { StreamContext } from "./stream-context";
 10→import type { SessionState } from "./claude-session";
