 12→// ============================================================================
 13→// Types
 14→// ============================================================================
 15→
 16→/** Options needed by processMessage that don't change per-message. */
 17→export interface ProcessMessageOptions {
 18→  sessionId: string;
 19→  generatorId: string;
 20→  model: string;
 21→  isResume: boolean;
 22→}
 23→
 24→// ============================================================================
 25→// deserializeMessage
 26→// ============================================================================
 27→
 28→/**
 29→ * Safely serializes and deserializes an SDK message to strip circular
 30→ * references and produce a clean Record<string, unknown>.
 31→ * Returns null if serialization fails (message should be skipped).
 32→ */
 33→export function deserializeMessage(
 34→  message: unknown,
 35→  generatorId: string
 36→): Record<string, unknown> | null {
 37→  try {
 38→    const seen = new WeakSet();
 39→    const messageStr = JSON.stringify(message, (_key, value) => {
 40→      if (typeof value === "object" && value !== null) {
 41→        if (seen.has(value)) return "[Circular]";
 42→        seen.add(value);
 43→      }
 44→      return value;
 45→    });
 46→    return JSON.parse(messageStr);
 47→  } catch (parseError) {
 48→    console.error(
 49→      `[${generatorId}] Failed to serialize/parse SDK message, skipping:`,
 50→      getErrorMessage(parseError)
 51→    );
 52→    return null;
 53→  }
 54→}
 55→
 56→// ============================================================================
 57→// processMessage
 58→// ============================================================================
 59→
 60→/**
 61→ * Processes a single deserialized SDK message.
 62→ *
 63→ * Side effects (in critical order):
 64→ * 1. Capture agent_session_id (one-shot, first message only, skip on resume)
 65→ * 2. Emit canonical message events (assistant, tool_result)
 66→ * 3. Send to frontend via JSON-RPC notification
 67→ * 4. Classify stop_reason and send error (AFTER sendMessage — content before error banner)
 68→ * 5. Detect result/success → set ctx.querySucceeded, emit session.idle
 69→ * 6. Detect result/error_during_execution → set ctx.lastResultError
 70→ *
 71→ * The agent-server is stateless — no DB writes. The backend persists messages
 72→ * and updates session status by consuming canonical events via the WS tunnel.
 73→ */
 74→export function processMessage(
 75→  cleanMessage: Record<string, unknown>,
 76→  ctx: StreamContext,
 77→  session: SessionState,
 78→  opts: ProcessMessageOptions
 79→): void {
 80→  // Extract common fields from the deserialized SDK message.
 81→  // cleanMessage is Record<string, unknown> (JSON.parse output), so
 82→  // we narrow once here instead of scattering `as` casts throughout.
 83→  const msg = cleanMessage.message as
 84→    | { id?: string; role?: string; content?: unknown; stop_reason?: string }
 85→    | undefined;
 86→  const parentToolUseId =
 87→    typeof cleanMessage.parent_tool_use_id === "string" ? cleanMessage.parent_tool_use_id : null;
 88→
 89→  // 1. One-shot: capture SDK session_id on the first message.
 90→  // CRITICAL: Skip capture during resume attempts. When a resume
 91→  // fails (result/error_during_execution), the SDK returns a NEW
 92→  // session_id that is useless. If we captured it, we'd overwrite
 93→  // the original working agent_session_id — permanently lost.
 94→  if (!session.agentSessionIdCaptured && cleanMessage.session_id && !opts.isResume) {
 95→    const agentSessionId = String(cleanMessage.session_id);
 96→
 97→    try {
 98→      // Emit canonical agent.session_id event — backend persists to DB.
 99→      // Set captured flag AFTER emission so a failed send allows retry on next message.
100→      EventBroadcaster.emitAgentSessionId(opts.sessionId, agentSessionId);
101→      session.agentSessionIdCaptured = true;
102→      console.log(`[${opts.generatorId}] Captured agent_session_id: ${agentSessionId}`);
103→    } catch (error) {
104→      console.error(
105→        `[${opts.generatorId}] Failed to emit agent_session_id:`,
106→        getErrorMessage(error)
107→      );
108→    }
109→  }
110→
111→  // 2. Emit canonical message events for assistant and tool_result messages
112→  if (cleanMessage.type === "assistant" && msg) {
113→    const assistantMsgId = msg.id || "unknown";
114→    EventBroadcaster.emitAssistantMessage(
115→      opts.sessionId,
116→      "claude",
117→      {
118→        id: assistantMsgId,
119→        role: "assistant",
120→        content: msg.content,
121→        stop_reason: msg.stop_reason ?? null,
122→        parent_tool_use_id: parentToolUseId,
123→      },
124→      opts.model
125→    );
126→  }
127→
128→  if (cleanMessage.type === "user" && msg) {
129→    const content = msg.content;
130→    const hasToolResult =
131→      Array.isArray(content) && content.some((b: any) => b?.type === "tool_result");
132→    if (hasToolResult) {
133→      const toolResultMsgId = msg.id || "unknown";
134→      EventBroadcaster.emitToolResultMessage(
135→        opts.sessionId,
136→        "claude",
137→        {
138→          id: toolResultMsgId,
139→          role: "user",
140→          content: msg.content,
141→          parent_tool_use_id: parentToolUseId,
142→        },
143→        opts.model
144→      );
145→    }
146→  }
147→
148→  // 3. Send to frontend via JSON-RPC notification
149→  const tSend = Date.now();
150→  EventBroadcaster.sendMessage({
151→    id: opts.sessionId,
152→    type: "message",
153→    agentType: "claude",
154→    data: cleanMessage,
155→  });
156→  const sendMs = Date.now() - tSend;
157→  if (sendMs > 5) {
158→    console.log(`[TIMING][${opts.generatorId}] sendMessage took ${sendMs}ms`);
159→  }
160→
161→  // 4. Classify stop_reason (after sendMessage — content before error banner)
162→  if (cleanMessage.type === "assistant" && msg) {
163→    const stopError = classifyStopReason(msg.stop_reason);
164→    if (stopError) {
165→      // Emit canonical session.error FIRST — backend handles DB status update.
166→      // This must succeed even if the frontend tunnel is down.
167→      EventBroadcaster.emitSessionError(
168→        opts.sessionId,
169→        "claude",
170→        stopError.message,
171→        stopError.category
172→      );
173→      // Then notify frontend (best-effort — don't let this block the canonical event)
174→      try {
175→        EventBroadcaster.sendError({
176→          id: opts.sessionId,
177→          type: "error",
178→          error: stopError.message,
179→          agentType: "claude",
180→          category: stopError.category,
181→        });
182→      } catch (error) {
183→        console.warn(
184→          `[${opts.generatorId}] Failed to send frontend error:`,
185→          getErrorMessage(error)
186→        );
187→      }
188→      ctx.stopReasonError = true;
189→    }
190→  }
191→
192→  // 5. result/success → mark query as succeeded and emit session.idle.
193→  // Must happen HERE (inside the loop), not in executeOutcome (post-loop),
194→  // because the streaming loop stays alive between turns — the prompt queue
195→  // blocks waiting for the next user message, so the post-loop never runs
196→  // until the entire conversation ends.
197→  if (cleanMessage.type === "result" && cleanMessage.subtype === "success") {
198→    ctx.querySucceeded = true;
199→
200→    // Emit canonical message.result event
201→    EventBroadcaster.emitMessageResult(opts.sessionId, "claude", "success");
202→
203→    if (!ctx.stopReasonError) {
204→      // Emit canonical session.idle — backend handles DB status update
205→      EventBroadcaster.emitSessionIdle(opts.sessionId, "claude");
206→    }
207→
208→    // Best-effort title fetch: after the first successful turn, ask the SDK
209→    // for its auto-generated session summary and emit it as a canonical event.
210→    // Fire-and-forget — title is cosmetic, don't block the stream.
211→    if (!ctx.titleEmitted && session.cwd) {
212→      ctx.titleEmitted = true;
213→      const sdkSessionId = cleanMessage.session_id ? String(cleanMessage.session_id) : null;
214→
215→      void (async () => {
216→        try {
217→          const { listSessions } = await import("@anthropic-ai/claude-agent-sdk");
218→          const sessions = await listSessions({ dir: session.cwd, limit: 20 });
219→          const matched = sdkSessionId
220→            ? sessions.find((s) => s.sessionId === sdkSessionId)
221→            : null;
222→          const title = matched?.summary;
223→          if (title) {
224→            EventBroadcaster.emitSessionTitle(opts.sessionId, "claude", title);
225→          }
226→        } catch (error) {
227→          console.error(
228→            `[${opts.generatorId}] Failed to fetch session title:`,
229→            getErrorMessage(error)
230→          );
231→        }
232→      })();
233→    }
234→  }
235→
236→  // 6. result/error_during_execution → capture for error diagnostics
237→  // NOTE: We intentionally do NOT clear the agent_session_id here.
238→  // Even if the resume failed, the original ID must be preserved.
239→  if (cleanMessage.type === "result" && cleanMessage.subtype === "error_during_execution") {
240→    const errors = cleanMessage.errors as string[] | undefined;
241→    const resultError =
242→      Array.isArray(errors) && errors.length > 0
243→        ? errors.join("; ")
244→        : typeof cleanMessage.error === "string"
245→          ? cleanMessage.error
246→          : "unknown";
247→    ctx.lastResultError = resultError;
248→    console.error(`[${opts.generatorId}] result/error_during_execution: ${resultError}`);
249→  }
250→}
251→

  1→// backend/src/services/agent/event-handler.ts
  2→// Receives canonical AgentEvent notifications from the agent-client and
  3→// dispatches them to persistence (DB writes) and WS push (query invalidation).
  4→//
  5→// This is the single entry point for all agent → backend data flow.
  6→// Each event is handled: persist first, then invalidate (ordering matters).
  7→//
  8→// Created via createAgentEventHandler() — a factory that injects the
  9→// respondToAgent dependency, breaking the circular import with service.ts.
 10→
 11→import { match } from "ts-pattern";
 12→import type { AgentEvent } from "@shared/agent-events";
 13→import type { QueryResource } from "@shared/types/query-protocol";
 14→import { invalidate } from "../query-engine";
 15→import { relay } from "./tool-relay";
 16→import {
 17→  persistAssistantMessage,
 18→  persistToolResultMessage,
 19→  persistMessageResult,
 20→  persistMessageCancelled,
 21→  persistSessionStarted,
 22→  persistSessionIdle,
 23→  persistSessionError,
 24→  persistSessionCancelled,
 25→  persistAgentSessionId,
 26→  persistSessionTitle,
 27→  type WriteResult,
 28→} from "./persistence";
 29→
 30→// ---- Types ----
 31→
 32→type RespondToAgentFn = (params: {
 33→  sessionId: string;
 34→  requestId: string;
 35→  result: unknown;
 36→}) => Promise<void>;
 37→
 38→export type AgentEventHandler = (event: AgentEvent) => void;
 39→
 40→// ---- Resource groups for invalidation ----
 41→
 42→const SESSION_RESOURCES: QueryResource[] = ["workspaces", "sessions", "session", "stats"];
 43→const MESSAGE_RESOURCES: QueryResource[] = ["messages", "session"];
 44→
 45→// ---- Helpers ----
 46→
 47→/** Persist an event and invalidate subscriptions if the write succeeded. */
 48→function persistAndInvalidate(
 49→  result: WriteResult<unknown>,
 50→  resources: QueryResource[],
 51→  sessionId: string
 52→): void {
 53→  if (result.ok) {
 54→    invalidate(resources, { sessionIds: [sessionId] });
 55→  }
 56→}
 57→
 58→// ---- Factory ----
 59→
 60→/**
 61→ * Create an agent event handler with injected dependencies.
 62→ *
 63→ * The respondToAgent function is injected to break the circular dependency
 64→ * between this module and service.ts. The composition root (service.ts)
 65→ * provides the concrete implementation: client.sendTurnRespond().
 66→ */
 67→export function createAgentEventHandler(deps: {
 68→  respondToAgent: RespondToAgentFn;
 69→}): AgentEventHandler {
 70→  const { respondToAgent } = deps;
 71→
 72→  return function handleAgentEvent(event: AgentEvent): void {
 73→    match(event)
 74→      // ── Session lifecycle ─────────────────────────────────────────────
 75→      .with({ type: "session.started" }, (e) => {
 76→        console.log(`[AgentEvent] session.started: session=${e.sessionId} agent=${e.agentType}`);
 77→        persistAndInvalidate(persistSessionStarted(e), SESSION_RESOURCES, e.sessionId);
 78→      })
 79→      .with({ type: "session.idle" }, (e) => {
 80→        console.log(`[AgentEvent] session.idle: session=${e.sessionId}`);
 81→        persistAndInvalidate(persistSessionIdle(e), SESSION_RESOURCES, e.sessionId);
 82→      })
 83→      .with({ type: "session.error" }, (e) => {
 84→        console.log(`[AgentEvent] session.error: session=${e.sessionId} error=${e.error}`);
 85→        persistAndInvalidate(persistSessionError(e), SESSION_RESOURCES, e.sessionId);
 86→      })
 87→      .with({ type: "session.cancelled" }, (e) => {
 88→        console.log(`[AgentEvent] session.cancelled: session=${e.sessionId}`);
 89→        persistAndInvalidate(persistSessionCancelled(e), SESSION_RESOURCES, e.sessionId);
 90→      })
 91→
 92→      // ── Messages ──────────────────────────────────────────────────────
 93→      .with({ type: "message.assistant" }, (e) => {
 94→        console.log(`[AgentEvent] message.assistant: session=${e.sessionId} msgId=${e.message.id}`);
 95→        persistAndInvalidate(persistAssistantMessage(e), MESSAGE_RESOURCES, e.sessionId);
 96→      })
 97→      .with({ type: "message.tool_result" }, (e) => {
 98→        console.log(
 99→          `[AgentEvent] message.tool_result: session=${e.sessionId} msgId=${e.message.id}`
100→        );
101→        persistAndInvalidate(persistToolResultMessage(e), MESSAGE_RESOURCES, e.sessionId);
102→      })
103→      .with({ type: "message.result" }, (e) => {
104→        console.log(`[AgentEvent] message.result: session=${e.sessionId} subtype=${e.subtype}`);
105→        persistMessageResult(e);
106→      })
107→      .with({ type: "message.cancelled" }, (e) => {
108→        console.log(`[AgentEvent] message.cancelled: session=${e.sessionId}`);
109→        persistAndInvalidate(
110→          persistMessageCancelled(e),
111→          ["messages", "sessions", "session", "stats"],
112→          e.sessionId
113→        );
114→      })
115→
116→      // ── Interaction requests ──────────────────────────────────────────
117→      .with({ type: "request.opened" }, (e) => {
118→        console.log(
119→          `[AgentEvent] request.opened: session=${e.sessionId} requestId=${e.requestId} type=${e.requestType}`
120→        );
121→      })
122→      .with({ type: "request.resolved" }, (e) => {
123→        console.log(
124→          `[AgentEvent] request.resolved: session=${e.sessionId} requestId=${e.requestId}`
125→        );
126→      })
127→
128→      // ── Tool relay ────────────────────────────────────────────────────
129→      .with({ type: "tool.request" }, (e) => {
130→        console.log(
131→          `[AgentEvent] tool.request: session=${e.sessionId} method=${e.method} requestId=${e.requestId}`
132→        );
133→        void relayToolRequest(e, respondToAgent);
134→      })
135→
136→      // ── Metadata ──────────────────────────────────────────────────────
137→      .with({ type: "agent.session_id" }, (e) => {
138→        console.log(
139→          `[AgentEvent] agent.session_id: session=${e.sessionId} agentSessionId=${e.agentSessionId}`
140→        );
141→        persistAndInvalidate(persistAgentSessionId(e), SESSION_RESOURCES, e.sessionId);
142→      })
143→      .with({ type: "session.title" }, (e) => {
144→        console.log(
145→          `[AgentEvent] session.title: session=${e.sessionId} title="${e.title}"`
146→        );
147→        persistAndInvalidate(persistSessionTitle(e), SESSION_RESOURCES, e.sessionId);
148→      })
149→
150→      .exhaustive();
151→  };
152→}
153→
154→// ---- Tool relay internal ----
155→
156→async function relayToolRequest(
157→  event: AgentEvent & { type: "tool.request" },
158→  respondToAgent: RespondToAgentFn
159→): Promise<void> {
160→  const { sessionId, requestId, method } = event;
161→
162→  try {
163→    const result = await relay(event);
164→    await respondToAgent({ sessionId, requestId, result });
165→    console.log(`[AgentEvent] tool.request resolved: requestId=${requestId} method=${method}`);
166→  } catch (err) {
167→    console.error(`[AgentEvent] tool.request failed: requestId=${requestId} method=${method}`, err);
168→    try {
169→      await respondToAgent({
170→        sessionId,
171→        requestId,
172→        result: { error: err instanceof Error ? err.message : "Tool relay failed" },
173→      });
174→    } catch (respondErr) {
175→      console.error(
176→        `[AgentEvent] Failed to send error response to agent: requestId=${requestId}`,
177→        respondErr
178→      );
179→    }
180→  }
181→}
182→

  1→// backend/src/services/agent/persistence.ts
  2→// Database write functions for persisting canonical agent events.
  3→//
  4→// Adapted from sidecar/db/session-writer.ts. Key differences:
  5→// - Uses backend's getDatabase() (not sidecar's)
  6→// - No notifyBackend() calls (backend handles WS push via invalidate())
  7→// - No FrontendClient calls (backend pushes via query-engine directly)
  8→// - Takes event objects instead of positional args
  9→//
 10→// All functions are synchronous (better-sqlite3 is synchronous).
 11→// Callers (event-handler.ts) call invalidate() after persistence succeeds.
 12→
 13→import { getDatabase } from "../../lib/database";
 14→import { uuidv7 } from "@shared/lib/uuid";
 15→import { getErrorMessage } from "@shared/lib/errors";
 16→import type {
 17→  MessageAssistantEvent,
 18→  MessageToolResultEvent,
 19→  MessageResultEvent,
 20→  MessageCancelledEvent,
 21→  SessionStartedEvent,
 22→  SessionIdleEvent,
 23→  SessionErrorEvent,
 24→  SessionCancelledEvent,
 25→  AgentSessionIdEvent,
 26→  SessionTitleEvent,
 27→} from "@shared/agent-events";
 28→
 29→// ============================================================================
 30→// WriteResult type (mirrors sidecar's pattern)
 31→// ============================================================================
 32→
 33→export type WriteResult<T = string> = { ok: true; value: T } | { ok: false; error: string };
 34→
 35→// ============================================================================
 36→// Message writes
 37→// ============================================================================
 38→
 39→/**
 40→ * Save an assistant message to the messages table.
 41→ * Mirrors sidecar saveAssistantMessage() logic:
 42→ * - Generates a local UUID7 message ID
 43→ * - Stores flat content array, except for cancelled messages which get an envelope
 44→ * - Records the agent_message_id and parent_tool_use_id for linking
 45→ */
 46→export function persistAssistantMessage(event: MessageAssistantEvent): WriteResult {
 47→  const db = getDatabase();
 48→  const messageId = uuidv7();
 49→  const sentAt = new Date().toISOString();
 50→
 51→  // Store flat content array for normal messages. For "cancelled" messages,
 52→  // write envelope so the frontend can detect cancellation from DB content.
 53→  const contentPayload =
 54→    event.message.stop_reason === "cancelled"
 55→      ? { message: { stop_reason: "cancelled" }, blocks: event.message.content ?? [] }
 56→      : (event.message.content ?? []);
 57→  const content = JSON.stringify(contentPayload);
 58→
 59→  try {
 60→    db.prepare(
 61→      `INSERT INTO messages (id, session_id, role, content, sent_at, model, agent_message_id, parent_tool_use_id)
 62→       VALUES (?, ?, 'assistant', ?, ?, ?, ?, ?)`
 63→    ).run(
 64→      messageId,
 65→      event.sessionId,
 66→      content,
 67→      sentAt,
 68→      event.model || null,
 69→      event.message.id || null,
 70→      event.message.parent_tool_use_id || null
 71→    );
 72→    return { ok: true, value: messageId };
 73→  } catch (error) {
 74→    const msg = getErrorMessage(error);
 75→    console.error(`[AgentPersistence] Failed to save assistant message:`, msg);
 76→    return { ok: false, error: msg };
 77→  }
 78→}
 79→
 80→/**
 81→ * Save a tool_result message (role='user') to the messages table.
 82→ * These contain tool execution results that link tool_use blocks to their outputs.
 83→ */
 84→export function persistToolResultMessage(event: MessageToolResultEvent): WriteResult {
 85→  const db = getDatabase();
 86→  const messageId = uuidv7();
 87→  const sentAt = new Date().toISOString();
 88→  const content = JSON.stringify(event.message.content ?? []);
 89→
 90→  try {
 91→    db.prepare(
 92→      `INSERT INTO messages (id, session_id, role, content, sent_at, agent_message_id, parent_tool_use_id)
 93→       VALUES (?, ?, 'user', ?, ?, ?, ?)`
 94→    ).run(
 95→      messageId,
 96→      event.sessionId,
 97→      content,
 98→      sentAt,
 99→      event.message.id || null,
100→      event.message.parent_tool_use_id || null
101→    );
102→    return { ok: true, value: messageId };
103→  } catch (error) {
104→    const msg = getErrorMessage(error);
105→    console.error(`[AgentPersistence] Failed to save tool_result message:`, msg);
106→    return { ok: false, error: msg };
107→  }
108→}
109→
110→/**
111→ * Handle message.result events. No DB write needed — this is informational
112→ * (success/error_during_execution subtypes). Session status transitions are
113→ * handled by separate session.idle / session.error events.
114→ */
115→export function persistMessageResult(_event: MessageResultEvent): void {
116→  // No-op: message.result is informational only.
117→  // Session status is managed by session.idle / session.error events.
118→}
119→
120→/**
121→ * Persist a cancellation: insert a cancelled assistant message marker
122→ * and set session status to idle.
123→ *
124→ * The cancelled message uses the envelope format so the frontend can detect
125→ * cancellation on reload (the "Turn interrupted" label in AssistantTurn).
126→ */
127→export function persistMessageCancelled(event: MessageCancelledEvent): WriteResult {
128→  const db = getDatabase();
129→  const messageId = uuidv7();
130→  const sentAt = new Date().toISOString();
131→
132→  // Empty cancelled message with envelope so frontend detects cancellation
133→  const content = JSON.stringify({
134→    message: { stop_reason: "cancelled" },
135→    blocks: [],
136→  });
137→
138→  try {
139→    db.transaction(() => {
140→      db.prepare(
141→        `INSERT INTO messages (id, session_id, role, content, sent_at, cancelled_at)
142→         VALUES (?, ?, 'assistant', ?, ?, ?)`
143→      ).run(messageId, event.sessionId, content, sentAt, sentAt);
144→
145→      db.prepare(
146→        `UPDATE sessions SET status = 'idle', error_message = NULL, error_category = NULL, updated_at = datetime('now') WHERE id = ?`
147→      ).run(event.sessionId);
148→    })();
149→
150→    return { ok: true, value: messageId };
151→  } catch (error) {
152→    const msg = getErrorMessage(error);
153→    console.error(`[AgentPersistence] Failed to persist message.cancelled:`, msg);
154→    return { ok: false, error: msg };
155→  }
156→}
157→
158→// ============================================================================
159→// Session status writes
160→// ============================================================================
161→
162→/**
163→ * Update session status to "working" when a turn starts.
164→ * Only updates if the session is not already working (idempotent).
165→ */
166→export function persistSessionStarted(event: SessionStartedEvent): WriteResult<void> {
167→  const db = getDatabase();
168→
169→  try {
170→    db.prepare(
171→      `UPDATE sessions SET status = 'working', error_message = NULL, error_category = NULL, updated_at = datetime('now')
172→       WHERE id = ? AND status != 'working'`
173→    ).run(event.sessionId);
174→    return { ok: true, value: undefined };
175→  } catch (error) {
176→    const msg = getErrorMessage(error);
177→    console.error(`[AgentPersistence] Failed to persist session.started:`, msg);
178→    return { ok: false, error: msg };
179→  }
180→}
181→
182→/** Update session status to "idle" when a turn completes. */
183→export function persistSessionIdle(event: SessionIdleEvent): WriteResult<void> {
184→  const db = getDatabase();
185→
186→  try {
187→    db.prepare(
188→      `UPDATE sessions SET status = 'idle', error_message = NULL, error_category = NULL, updated_at = datetime('now') WHERE id = ?`
189→    ).run(event.sessionId);
190→    return { ok: true, value: undefined };
191→  } catch (error) {
192→    const msg = getErrorMessage(error);
193→    console.error(`[AgentPersistence] Failed to persist session.idle:`, msg);
194→    return { ok: false, error: msg };
195→  }
196→}
197→
198→/** Update session status to "error" with error details. */
199→export function persistSessionError(event: SessionErrorEvent): WriteResult<void> {
200→  const db = getDatabase();
201→
202→  try {
203→    db.prepare(
204→      `UPDATE sessions SET status = 'error', error_message = ?, error_category = ?, updated_at = datetime('now') WHERE id = ?`
205→    ).run(event.error, event.category, event.sessionId);
206→    return { ok: true, value: undefined };
207→  } catch (error) {
208→    const msg = getErrorMessage(error);
209→    console.error(`[AgentPersistence] Failed to persist session.error:`, msg);
210→    return { ok: false, error: msg };
211→  }
212→}
213→
214→/** Update session status after cancellation (back to idle). */
215→export function persistSessionCancelled(event: SessionCancelledEvent): WriteResult<void> {
216→  const db = getDatabase();
217→
218→  try {
219→    db.prepare(
220→      `UPDATE sessions SET status = 'idle', error_message = NULL, error_category = NULL, updated_at = datetime('now') WHERE id = ?`
221→    ).run(event.sessionId);
222→    return { ok: true, value: undefined };
223→  } catch (error) {
224→    const msg = getErrorMessage(error);
225→    console.error(`[AgentPersistence] Failed to persist session.cancelled:`, msg);
226→    return { ok: false, error: msg };
227→  }
228→}
229→
230→// ============================================================================
231→// Metadata writes
232→// ============================================================================
233→
234→/** Store the agent-provider session ID for resume support. */
235→export function persistAgentSessionId(event: AgentSessionIdEvent): WriteResult<void> {
236→  const db = getDatabase();
237→
238→  try {
239→    db.prepare(
240→      `UPDATE sessions SET agent_session_id = ?, updated_at = datetime('now') WHERE id = ?`
241→    ).run(event.agentSessionId, event.sessionId);
242→    return { ok: true, value: undefined };
243→  } catch (error) {
244→    const msg = getErrorMessage(error);
245→    console.error(`[AgentPersistence] Failed to persist agent.session_id:`, msg);
246→    return { ok: false, error: msg };
247→  }
248→}
249→
250→/** Update session title and auto-set workspace title if not already set. */
251→export function persistSessionTitle(event: SessionTitleEvent): WriteResult<void> {
252→  const db = getDatabase();
253→
254→  try {
255→    db.transaction(() => {
256→      // Always update session title
257→      db.prepare(
258→        `UPDATE sessions SET title = ?, updated_at = datetime('now') WHERE id = ?`
259→      ).run(event.title, event.sessionId);
260→
261→      // Auto-set workspace title only if not already set (preserves PR titles and user renames)
262→      db.prepare(
263→        `UPDATE workspaces SET title = ?
264→         WHERE id = (SELECT workspace_id FROM sessions WHERE id = ?)
265→         AND title IS NULL`
266→      ).run(event.title, event.sessionId);
267→    })();
268→    return { ok: true, value: undefined };
269→  } catch (error) {
270→    const msg = getErrorMessage(error);
271→    console.error(`[AgentPersistence] Failed to persist session.title:`, msg);
272→    return { ok: false, error: msg };
273→  }
274→}
