  1→// sidecar/agents/codex/codex-handler.ts
  2→// CodexAgentHandler — implements AgentHandler for the OpenAI Codex SDK.
  3→// Mirrors the Claude handler architecture: streaming events, canonical event
  4→// emission, and frontend notifications via EventBroadcaster.
  5→// The agent-server is stateless — all DB writes handled by the backend.
  6→
  7→// Type-only imports are erased at compile time — safe for CJS bundling.
  8→// The runtime Codex class is loaded via dynamic import() in processQuery()
  9→// because @openai/codex-sdk is ESM-only and uses import.meta.url at module
 10→// init, which can't be shimmed in esbuild's CJS output.
 11→import type { ThreadItem, ThreadOptions } from "@openai/codex-sdk";
 12→import { match, P } from "ts-pattern";
 13→import { EventBroadcaster } from "../../event-broadcaster";
 14→import { classifyError, handleCancellation, handleQueryError } from "../lifecycle";
 15→import type { AgentCapabilities, AgentHandler, QueryOptions } from "../registry";
 16→import { buildAgentEnvironment, buildWorkspaceContext } from "../environment";
 17→import { initializeCodex, blockIfNotInitialized, getCodexExecutablePath } from "./codex-discovery";
 18→import { resolveCodexModel } from "./codex-models";
 19→import { codexSessions, abortCodexSession, type CodexSessionState } from "./codex-session";
 20→
 21→// ============================================================================
 22→// Message Format Mapping
 23→// ============================================================================
 24→
 25→/**
 26→ * Maps a Codex ThreadItem to Claude-compatible content blocks.
 27→ * The frontend renders messages using Claude's format (TextBlock, ToolUseBlock,
 28→ * ToolResultBlock, ThinkingBlock), so we produce the same shape.
 29→ */
 30→function mapItemToContentBlocks(item: ThreadItem): unknown[] {
 31→  return match(item)
 32→    .with({ type: "agent_message" }, (i) => [{ type: "text", text: i.text }])
 33→    .with({ type: "reasoning" }, (i) => [{ type: "thinking", thinking: i.text }])
 34→    .with({ type: "command_execution" }, (cmd) => {
 35→      const toolUseId = `codex-cmd-${cmd.id}`;
 36→      const blocks: unknown[] = [
 37→        {
 38→          type: "tool_use",
 39→          id: toolUseId,
 40→          name: "Bash",
 41→          input: { command: cmd.command },
 42→        },
 43→      ];
 44→      if (cmd.status === "completed" || cmd.status === "failed") {
 45→        blocks.push({
 46→          type: "tool_result",
 47→          tool_use_id: toolUseId,
 48→          content: cmd.aggregated_output || `Exit code: ${cmd.exit_code ?? "unknown"}`,
 49→          is_error: cmd.status === "failed" || (cmd.exit_code !== undefined && cmd.exit_code !== 0),
 50→        });
 51→      }
 52→      return blocks;
 53→    })
 54→    .with({ type: "file_change" }, (fc) => {
 55→      const toolUseId = `codex-file-${fc.id}`;
 56→      const summary = fc.changes.map((c) => `${c.kind}: ${c.path}`).join("\n");
 57→      return [
 58→        {
 59→          type: "tool_use",
 60→          id: toolUseId,
 61→          name: "Edit",
 62→          input: {
 63→            file_path: fc.changes[0]?.path ?? "unknown",
 64→            description: summary,
 65→          },
 66→        },
 67→        {
 68→          type: "tool_result",
 69→          tool_use_id: toolUseId,
 70→          content: summary,
 71→          is_error: fc.status === "failed",
 72→        },
 73→      ];
 74→    })
 75→    .with({ type: "mcp_tool_call" }, (mcp) => {
 76→      const toolUseId = `codex-mcp-${mcp.id}`;
 77→      const blocks: unknown[] = [
 78→        {
 79→          type: "tool_use",
 80→          id: toolUseId,
 81→          name: `${mcp.server}:${mcp.tool}`,
 82→          input: mcp.arguments ?? {},
 83→        },
 84→      ];
 85→      if (mcp.status === "completed" || mcp.status === "failed") {
 86→        blocks.push({
 87→          type: "tool_result",
 88→          tool_use_id: toolUseId,
 89→          content: mcp.error?.message ?? JSON.stringify(mcp.result ?? ""),
 90→          is_error: mcp.status === "failed",
 91→        });
 92→      }
 93→      return blocks;
 94→    })
 95→    .with({ type: "web_search" }, (ws) => [
 96→      {
 97→        type: "tool_use",
 98→        id: `codex-ws-${ws.id}`,
 99→        name: "WebSearch",
100→        input: { query: ws.query },
101→      },
102→    ])
103→    .with({ type: "todo_list" }, (todo) => {
104→      const text = todo.items.map((t) => `${t.completed ? "[x]" : "[ ]"} ${t.text}`).join("\n");
105→      return [{ type: "text", text: `**Plan:**\n${text}` }];
106→    })
107→    .with({ type: "error" }, (i) => [{ type: "text", text: `Error: ${i.message}` }])
108→    .otherwise((i) => {
109→      // External SDK types can gain new variants — gracefully ignore unknown items
110→      console.warn(`[codex] Unknown ThreadItem type: ${(i as any).type}`);
111→      return [];
112→    });
113→}
114→
115→// ============================================================================
116→// CodexAgentHandler
117→// ============================================================================
118→
119→export class CodexAgentHandler implements AgentHandler {
120→  readonly agentType = "codex" as const;
121→  readonly capabilities: AgentCapabilities = {
122→    auth: false,
123→    workspaceInit: false,
124→    contextUsage: false,
125→    permissionMode: false,
126→    modelSwitch: "unsupported",
127→    multiTurn: false,
128→    sessionResume: false,
129→  };
130→
131→  initialize(): { success: boolean; error?: string } {
132→    return initializeCodex();
133→  }
134→
135→  async query(sessionId: string, prompt: string, options: QueryOptions): Promise<void> {
136→    console.log("Handling Codex query request for session:", sessionId);
137→    if (blockIfNotInitialized(sessionId)) return;
138→
139→    const existingSession = codexSessions.get(sessionId);
140→
141→    // If a query is already running, we can't send a new one (Codex exec is not multi-turn streaming)
142→    if (existingSession?.isRunning) {
143→      console.log(`Codex session ${sessionId} already running, aborting previous run`);
144→      abortCodexSession(sessionId);
145→    }
146→
147→    void this.processQuery(sessionId, prompt, options, existingSession?.threadId);
148→  }
149→
150→  async cancel(sessionId: string): Promise<void> {
151→    console.log("Handling Codex cancel request for session:", sessionId);
152→    if (blockIfNotInitialized(sessionId)) return;
153→
154→    // Signal abort — processQuery's post-loop/catch path owns the
155→    // status transition via persistCancellation (sets idle + notifies frontend).
156→    abortCodexSession(sessionId);
157→  }
158→
159→  reset(sessionId: string): void {
160→    console.log(`Handling reset generator request for Codex session: ${sessionId}`);
161→    abortCodexSession(sessionId);
162→    codexSessions.delete(sessionId);
163→  }
164→
165→  // ==========================================================================
166→  // Private methods
167→  // ==========================================================================
168→
169→  private async processQuery(
170→    sessionId: string,
171→    prompt: string,
172→    options: QueryOptions,
173→    existingThreadId?: string
174→  ): Promise<void> {
175→    const queryId = `${sessionId}/${Date.now()}`;
176→    const abortController = new AbortController();
177→
178→    const session: CodexSessionState = {
179→      threadId: existingThreadId,
180→      abortController,
181→      currentModel: options.model,
182→      cwd: options.cwd,
183→      isRunning: true,
184→    };
185→    codexSessions.set(sessionId, session);
186→
187→    try {
188→      // Build environment (reuse shared env builder)
189→      const env = buildAgentEnvironment({
190→        providerEnvVars: options?.providerEnvVars,
191→        opendevsEnv: options?.opendevsEnv,
192→        ghToken: options?.ghToken,
193→      });
194→
195→      // Extract API key from environment
196→      const apiKey = env.OPENAI_API_KEY || env.CODEX_API_KEY;
197→      if (!apiKey) {
198→        throw new Error(
199→          "OPENAI_API_KEY or CODEX_API_KEY not found in environment. " +
200→            "Set it in Settings → Environment Variables."
201→        );
202→      }
203→
204→      const model = resolveCodexModel(options?.model);
205→      const codexPath = getCodexExecutablePath();
206→
207→      // Dynamic import — @openai/codex-sdk is ESM-only, can't be require()'d from CJS
208→      const { Codex } = await import("@openai/codex-sdk");
209→
210→      // Inject workspace context via config.developer_instructions
211→      // so it lands in the system prompt, not the user message.
212→      const workspaceContext = buildWorkspaceContext(options?.cwd);
213→      const codex = new Codex({
214→        apiKey,
215→        codexPathOverride: codexPath || undefined,
216→        env,
217→        ...(workspaceContext ? { config: { developer_instructions: workspaceContext } } : {}),
218→      });
219→
220→      // Configure thread options
221→      const threadOptions: ThreadOptions = {
222→        model,
223→        workingDirectory: options?.cwd,
224→        sandboxMode: "workspace-write",
225→        approvalPolicy: "never",
226→        skipGitRepoCheck: true,
227→        additionalDirectories: options?.additionalDirectories,
228→      };
229→
230→      // Start or resume thread
231→      const thread = existingThreadId
232→        ? codex.resumeThread(existingThreadId, threadOptions)
233→        : codex.startThread(threadOptions);
234→
235→      // Run streamed
236→      const { events } = await thread.runStreamed(prompt, {
237→        signal: abortController.signal,
238→      });
239→
240→      for await (const event of events) {
241→        if (abortController.signal.aborted) break;
242→
243→        match(event)
244→          .with({ type: "thread.started" }, (e) => {
245→            session.threadId = e.thread_id;
246→            console.log(`[${queryId}] Thread started: ${e.thread_id}`);
247→          })
248→          .with({ type: P.union("item.started", "item.updated", "item.completed") }, (e) => {
249→            const blocks = mapItemToContentBlocks(e.item);
250→            if (blocks.length === 0) return;
251→
252→            // Stable ID per item — same across started/updated/completed phases
253→            const msgId = `codex-${e.item.id}`;
254→
255→            // Send real-time update to frontend (every event, not just completed)
256→            EventBroadcaster.sendMessage({
257→              id: sessionId,
258→              type: "message",
259→              agentType: "codex",
260→              data: {
261→                type: "assistant" as const,
262→                message: {
263→                  id: msgId,
264→                  role: "assistant" as const,
265→                  content: blocks,
266→                },
267→              },
268→            });
269→
270→            // Only emit canonical event on item.completed to avoid duplicate DB records
271→            if (e.type === "item.completed") {
272→              EventBroadcaster.emitAssistantMessage(
273→                sessionId,
274→                "codex",
275→                {
276→                  id: msgId,
277→                  role: "assistant",
278→                  content: blocks,
279→                },
280→                model
281→              );
282→            }
283→          })
284→          .with({ type: "turn.completed" }, (e) => {
285→            console.log(
286→              `[${queryId}] Turn completed. Tokens: in=${e.usage.input_tokens}, out=${e.usage.output_tokens}`
287→            );
288→
289→            EventBroadcaster.sendMessage({
290→              id: sessionId,
291→              type: "message",
292→              agentType: "codex",
293→              data: {
294→                type: "result",
295→                subtype: "success",
296→                usage: e.usage,
297→              },
298→            });
299→
300→            // Emit canonical events — backend handles DB status update
301→            EventBroadcaster.emitMessageResult(sessionId, "codex", "success", e.usage);
302→            EventBroadcaster.emitSessionIdle(sessionId, "codex");
303→          })
304→          .with({ type: "turn.failed" }, (e) => {
305→            const classified = classifyError(e.error);
306→            console.error(`[${queryId}] Turn failed [${classified.category}]:`, classified.message);
307→            handleQueryError(sessionId, "codex", e.error);
308→          })
309→          .with({ type: "error" }, (e) => {
310→            const classified = classifyError(e);
311→            console.error(
312→              `[${queryId}] Stream error [${classified.category}]:`,
313→              classified.message
314→            );
315→            handleQueryError(sessionId, "codex", e);
316→          })
317→          .with({ type: "turn.started" }, () => {
318→            // Informational — no action needed
319→          })
320→          .otherwise((e) => {
321→            // External SDK types can gain new variants — gracefully skip unknown events
322→            console.warn(`[codex] Unknown ThreadEvent type: ${(e as any).type}`);
323→          });
324→      }
325→
326→      // Only update status if this processQuery still owns the session —
327→      // a rapid re-query can replace the session before we reach this point.
328→      if (codexSessions.owns(sessionId, session)) {
329→        if (abortController.signal.aborted) {
330→          // Abort break path: notify frontend + emit canonical events
331→          handleCancellation(sessionId, "codex", resolveCodexModel(options?.model), true);
332→        }
333→        // Note: no fallback idle emission here — turn.completed already emits it.
334→        // Emitting again would give the backend duplicate terminal lifecycle events.
335→      }
336→
337→      console.log(`[${queryId}] Codex session completed: ${sessionId}`);
338→    } catch (error) {
339→      const raw = classifyError(error);
340→      // Also treat abortController.signal.aborted as abort (codex-specific:
341→      // the error itself might not say "abort" but the signal was triggered)
342→      const isAbort = raw.category === "abort" || abortController.signal.aborted;
343→      console.error(
344→        `[${queryId}] Error in Codex query [${isAbort ? "abort" : raw.category}]:`,
345→        raw.message
346→      );
347→
348→      // Only update status if this processQuery still owns the session.
349→      if (codexSessions.owns(sessionId, session)) {
350→        if (isAbort) {
351→          handleCancellation(sessionId, "codex", resolveCodexModel(options?.model), true);
352→        } else {
353→          handleQueryError(sessionId, "codex", error);
354→        }
355→      }
356→    } finally {
357→      // Only clean up if this processQuery still owns the session.
358→      // A rapid re-query can replace the session before this finally runs;
359→      // blindly mutating would corrupt the new session's state.
360→      if (codexSessions.owns(sessionId, session)) {
361→        session.isRunning = false;
362→      }
363→    }
364→  }
365→}
366→

