  const commandPaletteOpen = useUIStore((s) => s.commandPaletteOpen);
  const anyDialogOpen = showNewWorkspaceModal || showSystemPromptModal || commandPaletteOpen || !!githubPickerRepoId;
  useEffect(() => {
    if (anyDialogOpen) {
      native.browserViews.hideAll().catch(() => {});
    }
  }, [anyDialogOpen]);

